                                {source.title}
                              </a>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex flex-col items-start animate-pulse">
                <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-2xl px-8 py-6 w-full space-y-4">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-purple-400 animate-bounce" />
                    <span className="text-xs font-orbitron text-purple-400 tracking-widest uppercase">Analyzing Data Streams...</span>
                  </div>
