                  <div className="h-4 bg-white/10 rounded w-5/6" />
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Persistent Decorative elements */}
      {!hasHistory && (
        <div className="fixed bottom-12 flex items-center gap-12 text-white/20 font-orbitron text-[10px] tracking-[0.4em] uppercase">
          <span>Global Search Grounding</span>
          <span>•</span>
          <span>Adaptive Reasoning</span>
          <span>•</span>
          <span>Encrypted Session</span>
        </div>
      )}

      {/* Footer / Status */}
      <footer className="fixed bottom-4 right-6 text-white/20 text-[10px] uppercase tracking-widest">
        System Status: Optimal
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { SearchResult } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // Initializing with the required API key from environment variables as per guidelines.
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async performSearch(query: string): Promise<SearchResult> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: query,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "I couldn't find an answer to that.";

      // Extract grounding sources from the response metadata. Using type assertion for flexible metadata access.
      const candidates = response.candidates || [];
      const groundingChunks = (candidates[0]?.groundingMetadata as any)?.groundingChunks || [];
      const sources: Array<{ title: string; uri: string }> = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web?.title || "Source",
          uri: chunk.web?.uri || ""
        }));

      // Create a unique set of sources based on their URI.
      // Explicitly type uniqueSources to resolve 'unknown[]' assignment error.
      const uniqueSources: Array<{ title: string; uri: string }> = Array.from(
        new Map(sources.map(s => [s.uri, s])).values()
      );

      return {
        text,
        sources: uniqueSources
      };
    } catch (error) {
      console.error("Gemini Search Error:", error);
      throw error;
    }
  }

  async *streamSearch(query: string) {
    try {
      const responseStream = await this.ai.models.generateContentStream({
        model: "gemini-3-flash-preview",
        contents: query,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        yield {
          text: c.text || "",
          done: false,
          sources: [] as Array<{ title: string; uri: string }>
        };
      }

      // Fetch full results at the end to provide accurate grounding metadata.
      const fullResponse = await this.performSearch(query);
      yield {
        ...fullResponse,
        done: true
      };
    } catch (error) {
      console.error("Gemini Stream Error:", error);
      throw error;
    }
  }
}

