                    {msg.content}
                  </div>
                ) : (
                  <div className="w-full space-y-4">
                    <div className="bg-white/5 border border-white/10 backdrop-blur-md rounded-2xl px-8 py-6 text-slate-200 leading-relaxed shadow-xl">
                      <div className="flex items-center gap-2 mb-4">
                        <div className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse" />
                        <span className="text-xs font-orbitron text-cyan-400 tracking-widest uppercase">Neural Response</span>
                      </div>
                      <div className="prose prose-invert max-w-none whitespace-pre-wrap">
                        {msg.content}
                      </div>

                      {msg.sources && msg.sources.length > 0 && (
                        <div className="mt-8 pt-6 border-t border-white/10">
                          <h4 className="text-xs font-semibold text-white/40 uppercase tracking-widest mb-3">Sources Grounding</h4>
                          <div className="flex flex-wrap gap-2">
