import React, { useEffect, useRef } from 'react';

const Background: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let particles: Particle[] = [];

    class Particle {
      x: number;
      y: number;
      size: number;
      speedX: number;
      speedY: number;
      color: string;
      baseSize: number;
      twinkleSpeed: number;
      twinkleOffset: number;

      constructor() {
        this.x = Math.random() * canvas!.width;
        this.y = Math.random() * canvas!.height;
        this.baseSize = Math.random() * 1.5 + 0.1;
        this.size = this.baseSize;
        this.speedX = (Math.random() - 0.5) * 0.3;
        this.speedY = (Math.random() - 0.5) * 0.3;
        const colors = ['#22d3ee', '#818cf8', '#c084fc'];
        this.color = colors[Math.floor(Math.random() * colors.length)];
        this.twinkleSpeed = 0.01 + Math.random() * 0.05;
        this.twinkleOffset = Math.random() * Math.PI * 2;
      }

      update() {
        this.x += this.speedX;
        this.y += this.speedY;

        // Twinkle effect
        this.size = this.baseSize * (1 + 0.5 * Math.sin(Date.now() * this.twinkleSpeed + this.twinkleOffset));

        if (this.x > canvas!.width) this.x = 0;
        else if (this.x < 0) this.x = canvas!.width;
        if (this.y > canvas!.height) this.y = 0;
        else if (this.y < 0) this.y = canvas!.height;
      }

      draw() {
        if (!ctx) return;
        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      particles = [];
      for (let i = 0; i < 120; i++) {
        particles.push(new Particle());
      }
    };

    const animate = () => {
      ctx.fillStyle = 'rgba(5, 5, 16, 0.25)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      particles.forEach(p => {
        p.update();
        p.draw();
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    init();
    animate();

    const handleResize = () => {
      init();
    };

    window.addEventListener('resize', handleResize);
    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <div className="fixed inset-0 -z-10 overflow-hidden bg-[#050510]">
      {/* Dynamic Pulsing Gradients */}
      <div className="absolute top-[-15%] left-[-10%] w-[60%] h-[60%] bg-cyan-900/10 blur-[130px] rounded-full animate-gradient-pulse" />
      <div className="absolute bottom-[-15%] right-[-10%] w-[60%] h-[60%] bg-purple-900/10 blur-[130px] rounded-full animate-gradient-pulse" style={{ animationDelay: '-5s' }} />

      {/* Animated Circuit Overlay */}
      <svg className="absolute inset-0 w-full h-full opacity-[0.12]" xmlns="http://www.w3.org/2000/svg">
        <defs>
          <pattern id="grid" width="100" height="100" patternUnits="userSpaceOnUse">
            <path d="M 100 0 L 0 0 0 100" fill="none" stroke="rgba(255,255,255,0.4)" strokeWidth="0.5" />
          </pattern>
          <mask id="circuit-mask">
            <rect width="100%" height="100%" fill="url(#grid)" />
          </mask>
        </defs>

        <rect width="100%" height="100%" fill="url(#grid)" />

        {/* Moving data streams along the grid */}
        <g stroke="cyan" strokeWidth="1" fill="none" opacity="0.6" style={{ mask: 'url(#circuit-mask)' }}>
          <path d="M 0 100 H 1000" strokeDasharray="10 190" className="animate-dash" />
          <path d="M 0 300 H 1000" strokeDasharray="20 180" className="animate-dash" style={{ animationDelay: '-2s', animationDuration: '12s' }} />
          <path d="M 0 500 H 1000" strokeDasharray="15 285" className="animate-dash" style={{ animationDelay: '-4s', animationDuration: '18s' }} />
          <path d="M 0 700 H 1000" strokeDasharray="30 170" className="animate-dash" style={{ animationDelay: '-1s', animationDuration: '10s' }} />
          <path d="M 0 900 H 1000" strokeDasharray="10 290" className="animate-dash" style={{ animationDelay: '-6s', animationDuration: '20s' }} />

          <path d="M 200 0 V 1000" strokeDasharray="20 180" className="animate-dash" style={{ animationDelay: '-3s', animationDuration: '14s' }} />
          <path d="M 400 0 V 1000" strokeDasharray="10 240" className="animate-dash" style={{ animationDelay: '-7s', animationDuration: '16s' }} />
          <path d="M 600 0 V 1000" strokeDasharray="15 135" className="animate-dash" style={{ animationDelay: '-2s', animationDuration: '11s' }} />
          <path d="M 800 0 V 1000" strokeDasharray="25 275" className="animate-dash" style={{ animationDelay: '-5s', animationDuration: '19s' }} />
        </g>
      </svg>

      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />
    </div>
  );
};

