  y: number;
  vx: number;
  vy: number;
  size: number;
  life: number;
  maxLife: number;
}

const SparkleTitle: React.FC<{ hasHistory: boolean }> = ({ hasHistory }) => {
  const [particles, setParticles] = useState<Particle[]>([]);
  const requestRef = useRef<number>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const nextId = useRef(0);

  const spawnParticle = useCallback((x: number, y: number) => {
    const p: Particle = {
      id: nextId.current++,
      x,
      y,
      vx: (Math.random() - 0.5) * 2,
      vy: (Math.random() - 0.5) * 2 - 1, // Tend upwards
      size: Math.random() * 3 + 1,
      life: 0,
      maxLife: Math.random() * 40 + 20,
    };
    setParticles((prev) => [...prev.slice(-20), p]); // Limit to 20 sparkles at a time
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    // Random chance to spawn on move to keep it "subtle"
    if (Math.random() > 0.7) {
      spawnParticle(x, y);
    }
  };

  useEffect(() => {
    const update = () => {
      setParticles((prev) => 
        prev
          .map((p) => ({
            ...p,
            x: p.x + p.vx,
            y: p.y + p.vy,
            life: p.life + 1,
            vy: p.vy + 0.02, // slight gravity
          }))
          .filter((p) => p.life < p.maxLife)
      );
      requestRef.current = requestAnimationFrame(update);
    };
    requestRef.current = requestAnimationFrame(update);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      className="relative group cursor-default select-none"
    >
      <h1 className={`font-orbitron font-bold tracking-widest text-white spark-glow transition-all duration-700 ${hasHistory ? 'text-4xl' : 'text-7xl mb-4'}`}>
        SPARK
      </h1>
      <div className="absolute -inset-2 bg-cyan-500/20 blur-xl opacity-0 group-hover:opacity-100 transition-opacity rounded-full pointer-events-none" />

      {particles.map((p) => (
        <div
          key={p.id}
          className="absolute rounded-full bg-cyan-300 pointer-events-none shadow-[0_0_8px_rgba(34,211,238,0.8)]"
          style={{
            left: p.x,
            top: p.y,
            width: p.size,
            height: p.size,
            opacity: 1 - p.life / p.maxLife,
            transform: `scale(${1 - p.life / p.maxLife})`,
          }}
        />
      ))}
    </div>
  );
};

