const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  const formatNeuralResponse = (content: string) => {
    // Remove Markdown header markers (#) and bold markers (**)
    return content
      .replace(/\*\*/g, '') // Strips all occurrences of **
      .replace(/^#+\s+/gm, '') // Strips # or ## at the start of any line
      .trim();
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim() || isLoading) return;

    const userQuery = query;
    setQuery('');
    setMessages(prev => [...prev, { role: 'user', content: userQuery }]);
    setIsLoading(true);
    setError(null);

    try {
      const stream = geminiService.streamSearch(userQuery);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = {
                ...newMsgs[newMsgs.length - 1],
                content: accumulatedText
              };
              return newMsgs;
            });
          }
        } else {
          // Final result chunk contains full text and sources
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { 
              role: 'assistant', 
              content: chunk.text, 
              sources: chunk.sources 
            }]);
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = {
                ...newMsgs[newMsgs.length - 1],
                content: chunk.text,
                sources: chunk.sources
              };
              return newMsgs;
            });
          }
        }
      }
    } catch (error: any) {
      setError("Failed to synchronize with the neural core. Error: " + (error?.message || "Internal Uplink Fault"));
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: "I'm sorry, I encountered a disruption in my neural connection. Please check the interference alert below." 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceSearch = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
      setError("Critical System Error: Neural Voice Capture (Web Speech API) is not supported by your current interface.");
      return;
    }

    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
      return;
    }

    setError(null);
    try {
      await navigator.mediaDevices.getUserMedia({ audio: true });

      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.interimResults = false;
      recognition.maxAlternatives = 1;

      recognition.onstart = () => {
        setIsListening(true);
      };

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setQuery(transcript);
        setIsListening(false);
      };

      recognition.onerror = (event: any) => {
        console.error("Speech recognition error:", event.error);
        if (event.error === 'not-allowed') {
          setError("Neural link failed: Voice access denied. Please recalibrate your security permissions in the browser.");
        } else {
          setError(`Signal Interference: Voice capture failed (${event.error}).`);
        }
        setIsListening(false);
      };

      recognition.onend = () => {
        setIsListening(false);
      };

      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) {
      console.error("Microphone access check failed:", err);
      setError("Neural link failed: Hardware initialization error. Ensure microphone is connected.");
      setIsListening(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;

  return (
    <div className="relative min-h-screen w-full overflow-hidden flex flex-col items-center">
      <Background />
      <FloatingElements />

      {/* Error Notifications */}
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      {/* Header */}
      <header className={`transition-all duration-700 w-full flex flex-col items-center pt-12 ${hasHistory ? 'h-32 pt-8' : 'h-[40vh] justify-center pt-0'}`}>
        <SparkleTitle hasHistory={hasHistory} />
        {!hasHistory && (
          <p className="text-cyan-400/80 font-medium tracking-[0.3em] uppercase text-xs animate-pulse">
            Neural Intelligence Interface
          </p>
        )}
      </header>

      {/* Search Bar Area */}
      <main className={`flex-1 w-full max-w-4xl px-6 transition-all duration-700 ${hasHistory ? 'mt-4' : 'mt-8'}`}>
        <form 
          onSubmit={handleSearch}
          className={`relative group w-full mb-8 z-10`}
        >
          <div className="search-container relative overflow-hidden rounded-2xl border border-cyan-500/30 bg-white/5 backdrop-blur-xl shadow-2xl glow-search hover:border-cyan-400/60 transition-all duration-300">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={isListening ? "Listening..." : "Ask Spark anything..."}
              className="w-full bg-transparent px-8 py-5 text-lg text-white placeholder-white/30 focus:outline-none focus:ring-0"
              autoFocus
            />

            <div className="absolute right-6 top-1/2 -translate-y-1/2 flex items-center gap-4">
              {/* Voice Search Button with Tooltip */}
              <div className="relative group/tooltip">
                <button 
                  type="button" 
                  onClick={toggleVoiceSearch}
                  className={`transition-all duration-300 p-2 rounded-full ${isListening ? 'text-red-400 bg-red-400/10 shadow-[0_0_15px_rgba(248,113,113,0.4)] animate-pulse' : 'text-cyan-400/60 hover:text-cyan-300 hover:bg-white/5'}`}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
                </button>
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 px-3 py-1.5 bg-black/80 backdrop-blur-md border border-cyan-500/30 rounded-lg text-[10px] text-cyan-300 font-orbitron uppercase tracking-widest whitespace-nowrap opacity-0 scale-95 group-hover/tooltip:opacity-100 group-hover/tooltip:scale-100 transition-all duration-200 pointer-events-none z-50 shadow-[0_0_15px_rgba(34,211,238,0.2)]">
                  Neural Voice Capture
                </div>
              </div>

              {/* Submit Button with Tooltip */}
              <div className="relative group/tooltip">
                <button 
                  type="submit" 
                  className={`p-2 bg-cyan-500/20 text-cyan-400/60 rounded-lg hover:bg-cyan-500/40 hover:text-cyan-300 transition-all ${isLoading ? 'animate-spin' : ''}`}
                  disabled={isLoading}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m22 2-7 20-4-9-9-4Z"/><path d="M22 2 11 13"/></svg>
                </button>
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 px-3 py-1.5 bg-black/80 backdrop-blur-md border border-cyan-500/30 rounded-lg text-[10px] text-cyan-300 font-orbitron uppercase tracking-widest whitespace-nowrap opacity-0 scale-95 group-hover/tooltip:opacity-100 group-hover/tooltip:scale-100 transition-all duration-200 pointer-events-none z-50 shadow-[0_0_15px_rgba(34,211,238,0.2)]">
                  Initialize Search
                </div>
