const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  const formatNeuralResponse = (content: string) => {
    return content.replace(/\*\*/g, '').replace(/^#+\s+/gm, '').trim();
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim() || isLoading) return;

    const userQuery = query;
    setQuery('');
    setMessages(prev => [...prev, { role: 'user', content: userQuery }]);
    setIsLoading(true);
    setError(null);

    try {
      const stream = geminiService.streamSearch(userQuery);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: chunk.text, sources: chunk.sources }]);
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: chunk.text, sources: chunk.sources };
              return newMsgs;
            });
          }
        }
      }
    } catch (error: any) {
      setError("Failed to synchronize with the neural core. Error: " + (error?.message || "Internal Uplink Fault"));
      setMessages(prev => [...prev, { role: 'assistant', content: "I encountered a disruption. Please check the interference alert." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceSearch = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { setError("Voice Capture not supported."); return; }
    if (isListening) { recognitionRef.current?.stop(); setIsListening(false); return; }
    setError(null);
    try {
      await navigator.mediaDevices.getUserMedia({ audio: true });
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onerror = () => setIsListening(false);
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setError("Neural link failed: Hardware error."); setIsListening(false); }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopySuccess(index);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const editMessage = (text: string) => {
    setQuery(text);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const allSources = useMemo(() => {
    const sourcesMap = new Map();
    messages.forEach(msg => {
      msg.sources?.forEach(s => sourcesMap.set(s.uri, s));
    });
    return Array.from(sourcesMap.values());
  }, [messages]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;

  return (
    <div className="relative min-h-screen w-full overflow-hidden flex flex-col items-center">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`transition-all duration-700 w-full flex flex-col items-center pt-12 ${hasHistory ? 'h-32 pt-8' : 'h-[40vh] justify-center pt-0'}`}>
        <SparkleTitle hasHistory={hasHistory} />
        {!hasHistory && <p className="text-cyan-400/80 font-medium tracking-[0.3em] uppercase text-xs animate-pulse">Neural Intelligence Interface</p>}
      </header>

      <main className={`flex-1 w-full max-w-4xl px-6 transition-all duration-700 ${hasHistory ? 'mt-4' : 'mt-8'}`}>
        <form onSubmit={handleSearch} className="relative group w-full mb-8 z-10">
          <div className="search-container relative overflow-hidden rounded-2xl border border-cyan-500/30 bg-white/5 backdrop-blur-xl shadow-2xl glow-search hover:border-cyan-400/60 transition-all duration-300">
            <input
              type="text" value={query} onChange={(e) => setQuery(e.target.value)}
              placeholder={isListening ? "Listening..." : "Ask Spark anything..."}
              className="w-full bg-transparent px-8 py-5 text-lg text-white placeholder-white/30 focus:outline-none focus:ring-0"
              autoFocus
            />
            <div className="absolute right-6 top-1/2 -translate-y-1/2 flex items-center gap-4">
              <button type="button" onClick={toggleVoiceSearch} className={`transition-all duration-300 p-2 rounded-full ${isListening ? 'text-red-400 bg-red-400/10' : 'text-cyan-400/60 hover:text-cyan-300'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
              </button>
              <button type="submit" className={`p-2 bg-cyan-500/20 text-cyan-400/60 rounded-lg hover:bg-cyan-500/40 hover:text-cyan-300 ${isLoading ? 'animate-spin' : ''}`} disabled={isLoading}>
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m22 2-7 20-4-9-9-4Z"/><path d="M22 2 11 13"/></svg>
              </button>
            </div>
            <div className="absolute bottom-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-cyan-400 to-transparent scale-x-0 group-focus-within:scale-x-100 transition-transform duration-500" />
          </div>
        </form>

        {hasHistory && (
          <div ref={scrollRef} className="flex flex-col gap-8 h-[calc(100vh-280px)] overflow-y-auto pb-10 scroll-smooth pr-2">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex flex-col group/msg ${msg.role === 'user' ? 'items-end' : 'items-start animate-in fade-in slide-in-from-bottom-4'}`}>
                <div className={`relative ${msg.role === 'user' ? 'bg-cyan-900/40 border-cyan-500/20 text-right pr-12' : 'bg-white/5 border-white/10 w-full'} border backdrop-blur-md rounded-2xl px-8 py-6 text-slate-200 leading-relaxed shadow-xl`}>
                  {msg.role === 'assistant' && (
                    <div className="flex items-center gap-2 mb-4">
                      <div className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse" />
                      <span className="text-xs font-orbitron text-cyan-400 tracking-widest uppercase">Neural Response</span>
                    </div>
                  )}

                  <div className="prose prose-invert max-w-none whitespace-pre-wrap">
                    {msg.role === 'assistant' ? formatNeuralResponse(msg.content) : msg.content}
                  </div>

                  {/* Actions Bar */}
                  <div className={`absolute top-4 right-4 flex items-center gap-2 transition-opacity duration-200 ${msg.role === 'user' ? '' : 'opacity-0 group-hover/msg:opacity-100'}`}>
                    {msg.role === 'user' ? (
                      <button onClick={() => editMessage(msg.content)} className="p-1.5 text-cyan-400/40 hover:text-cyan-400 transition-colors" title="Edit Message">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                      </button>
                    ) : (
                      <button onClick={() => copyToClipboard(msg.content, idx)} className="p-1.5 text-cyan-400/40 hover:text-cyan-400 transition-colors" title="Copy Response">
                        {copySuccess === idx ? (
                          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-green-400"><path d="M20 6 9 17l-5-5"/></svg>
                        ) : (
                          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
                        )}
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
            {isLoading && <CyberLoader />}

            {/* Aggregate Global Sources Section */}
            {allSources.length > 0 && <SourcesDisplay sources={allSources} />}
          </div>
        )}
      </main>
      {!hasHistory && <div className="fixed bottom-12 flex items-center gap-12 text-white/20 font-orbitron text-[10px] tracking-[0.4em] uppercase"><span>Global Search Grounding</span><span>•</span><span>Adaptive Reasoning</span><span>•</span><span>Encrypted Session</span></div>}
      <footer className="fixed bottom-4 right-6 text-white/20 text-[10px] uppercase tracking-widest">System Status: Optimal</footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';

interface Source {
  title: string;
  uri: string;
}

interface SourcesDisplayProps {
  sources: Source[];
}

const SourcesDisplay: React.FC<SourcesDisplayProps> = ({ sources }) => {
  const [selectedDomain, setSelectedDomain] = useState<string | null>(null);

  const domains = useMemo(() => {
    const domainMap = new Map<string, number>();
    sources.forEach(source => {
      try {
        const domain = new URL(source.uri).hostname.replace('www.', '');
        domainMap.set(domain, (domainMap.get(domain) || 0) + 1);
      } catch (e) {
        domainMap.set('unknown', (domainMap.get('unknown') || 0) + 1);
      }
    });
    return Array.from(domainMap.entries()).sort((a, b) => b[1] - a[1]);
  }, [sources]);

  const filteredSources = useMemo(() => {
    if (!selectedDomain) return sources;
    return sources.filter(source => {
      try {
        return new URL(source.uri).hostname.replace('www.', '') === selectedDomain;
      } catch {
        return selectedDomain === 'unknown';
      }
    });
  }, [sources, selectedDomain]);

  if (sources.length === 0) return null;

  return (
    <div className="mt-12 pt-10 border-t border-cyan-500/20 animate-in fade-in duration-1000">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-8">
