        {/* Domain Filters */}
        <div className="flex flex-wrap gap-2">
          <button
            onClick={() => setSelectedDomain(null)}
            className={`px-3 py-1.5 rounded-lg text-[10px] font-orbitron transition-all duration-300 border ${
              selectedDomain === null 
                ? 'bg-cyan-500/20 border-cyan-400/50 text-cyan-300 shadow-[0_0_15px_rgba(34,211,238,0.2)]' 
                : 'bg-white/5 border-white/10 text-white/40 hover:text-white/60 hover:bg-white/10'
            }`}
          >
            All Signal Sources
          </button>
          {domains.map(([domain, count]) => (
            <button
              key={domain}
              onClick={() => setSelectedDomain(domain === selectedDomain ? null : domain)}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-orbitron transition-all duration-300 border flex items-center gap-2 ${
