      {/* Filtered Results */}
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3 transition-all duration-500">
        {filteredSources.map((source, sIdx) => (
          <a 
            key={sIdx}
            href={source.uri}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center gap-3 px-4 py-3 rounded-xl bg-white/[0.03] border border-white/5 hover:bg-cyan-500/10 hover:border-cyan-500/40 transition-all group/link animate-in zoom-in-95 fade-in duration-300"
          >
            <div className="p-2 rounded-lg bg-cyan-500/10 text-cyan-400 group-hover/link:bg-cyan-400 group-hover/link:text-black transition-colors">
              <svg 
                className="group-hover/link:rotate-45 transition-transform duration-300" 
                xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
              >
