          {messages.map((msg, idx) => (
            <div key={idx} className={`animate-result group/msg w-full flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`relative max-w-[90%] md:max-w-[85%] border backdrop-blur-md rounded-2xl px-6 py-5 text-slate-200 leading-relaxed shadow-lg ${msg.role === 'user' ? 'bg-cyan-900/20 border-cyan-500/20' : 'bg-white/[0.03] border-white/10 w-full'}`}>
