                  {msg.role === 'assistant' ? formatNeuralResponse(msg.content) : msg.content}
                </div>

                {/* Hidden Actions that appear on hover */}
                <div className="absolute top-3 right-3 flex gap-2 opacity-0 group-hover/msg:opacity-100 transition-opacity">
                  {msg.role === 'user' ? (
                    <button onClick={() => editMessage(msg.content)} className="p-1.5 text-white/20 hover:text-cyan-400">
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                    </button>
