import SourcesDisplay from './components/SourcesDisplay';
import { geminiService } from './services/geminiService';
import { ChatMessage, SearchResult } from './types';

const SparkleTitle: React.FC<{ hasHistory: boolean }> = ({ hasHistory }) => {
