        Spark
      </h1>
      <div className={`h-[1px] bg-gradient-to-r from-transparent via-white/10 to-transparent mt-3 transition-all duration-1000 ${hasHistory ? 'w-4 opacity-0' : 'w-24 opacity-100'}`} />
    </div>
  );
};

const CyberLoader: React.FC = () => {
  return (
    <div className="w-full py-16 flex flex-col items-center justify-center animate-result">
      <div className="relative w-8 h-8">
        <div className="absolute inset-0 rounded-full border-[1.5px] border-white/5 border-t-cyan-500/40 animate-spin" />
