const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<number | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  const formatNeuralResponse = (content: string) => {
    return content.replace(/\*\*/g, '').replace(/^#+\s+/gm, '').trim();
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim() || isLoading) return;

    const userQuery = query;
    setQuery('');
    setMessages(prev => [...prev, { role: 'user', content: userQuery }]);
    setIsLoading(true);
    setError(null);

    try {
      const stream = geminiService.streamSearch(userQuery);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          setMessages(prev => {
            const newMsgs = [...prev];
            newMsgs[newMsgs.length - 1] = { 
              ...newMsgs[newMsgs.length - 1], 
              content: chunk.text, 
              sources: chunk.sources 
            };
            return newMsgs;
          });
        }
      }
    } catch (error: any) {
      setError("Neutral connection interrupted. Uplink failover initiated.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceSearch = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopySuccess(index);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const editMessage = (text: string) => {
    setQuery(text);
  };

  const allSources = useMemo(() => {
    const sourcesMap = new Map();
    messages.forEach(msg => msg.sources?.forEach(s => sourcesMap.set(s.uri, s)));
    return Array.from(sourcesMap.values());
  }, [messages]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;

  return (
    <div className="relative h-screen w-full overflow-hidden flex flex-col items-center">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      {/* Minimal Header */}
      <header className={`layout-transition fixed top-0 w-full z-[60] flex ${hasHistory ? 'h-24' : 'h-[35vh] items-end pb-12 justify-center'}`}>
        <SparkleTitle hasHistory={hasHistory} />
      </header>

      {/* Staggered Results Area */}
      <main 
        ref={scrollRef}
        className={`layout-transition w-full max-w-4xl px-8 overflow-y-auto overflow-x-hidden flex flex-col ${hasHistory ? 'pt-40 pb-48 opacity-100' : 'h-0 opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-14">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className="animate-result group/msg w-full flex flex-col"
              style={{ animationDelay: `${idx * 0.1}s` }}
            >
              <div className={`relative max-w-full border glass-card rounded-2xl px-10 py-8 text-slate-100 leading-relaxed transition-all duration-700 hover:border-white/10 ${msg.role === 'user' ? 'border-white/5 bg-white/[0.01]' : 'border-white/[0.03]'}`}>
                {msg.role === 'assistant' && (
                  <div className="flex items-center gap-3 mb-6">
                    <div className="w-1 h-1 rounded-full bg-cyan-400/30" />
                    <span className="text-[9px] font-semibold text-white/20 uppercase tracking-[0.4em]">Synthesis</span>
                  </div>
                )}

                <div className="text-[15px] md:text-[17px] prose prose-invert max-w-none whitespace-pre-wrap font-light tracking-wide opacity-80">
                  {msg.role === 'assistant' ? formatNeuralResponse(msg.content) : msg.content}
                </div>

                <div className={`absolute top-6 right-8 flex gap-4 transition-opacity duration-500 ${msg.role === 'user' ? 'opacity-20 group-hover/msg:opacity-100' : 'opacity-0 group-hover/msg:opacity-100'}`}>
                  {msg.role === 'user' ? (
                    <button onClick={() => editMessage(msg.content)} className="p-1 text-white/20 hover:text-cyan-400 transition-colors">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                    </button>
                  ) : (
                    <button onClick={() => copyToClipboard(msg.content, idx)} className="p-1 text-white/20 hover:text-cyan-400 transition-colors">
                      {copySuccess === idx ? (
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-green-500/50"><path d="M20 6 9 17l-5-5"/></svg>
                      ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
                      )}
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
          {isLoading && <CyberLoader />}
          {allSources.length > 0 && !isLoading && (
            <div className="animate-result" style={{ animationDelay: '0.4s' }}>
              <SourcesDisplay sources={allSources} />
            </div>
          )}
        </div>
      </main>

      {/* Formal Search Bar */}
      <div className={`layout-transition fixed left-0 right-0 px-6 flex justify-center z-[70] pointer-events-none ${hasHistory ? 'bottom-12' : 'top-1/2 -translate-y-1/2'}`}>
        <form 
          onSubmit={handleSearch} 
          className="w-full max-w-2xl pointer-events-auto"
        >
          <div className="search-container relative overflow-hidden rounded-full border border-white/[0.04] bg-white/[0.02] backdrop-blur-[30px]">
            <input
              type="text" value={query} onChange={(e) => setQuery(e.target.value)}
              placeholder={isListening ? "Listening..." : "How can Spark assist you today?"}
              className="w-full bg-transparent px-12 py-7 text-white placeholder-white/10 focus:outline-none focus:ring-0 text-[17px] font-light tracking-wide"
              autoFocus
            />
            <div className="absolute right-6 top-1/2 -translate-y-1/2 flex items-center gap-4">
              <button 
                type="button" 
                onClick={toggleVoiceSearch} 
                className={`p-3 rounded-full transition-all duration-700 ${isListening ? 'text-red-400 bg-red-400/5' : 'text-white/10 hover:text-white/40 hover:bg-white/5'}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
              </button>
              <button 
                type="submit" 
                disabled={isLoading}
                className={`p-3 bg-white/5 text-white/20 rounded-full hover:bg-white/10 hover:text-white/60 transition-all duration-500 ${isLoading ? 'opacity-30' : ''}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m22 2-7 20-4-9-9-4Z"/><path d="M22 2 11 13"/></svg>
              </button>
            </div>
          </div>
        </form>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-16 flex items-center gap-12 text-white/5 text-[9px] tracking-[0.8em] uppercase pointer-events-none select-none font-medium">
          <span>Grounded Intelligence</span>
          <span>•</span>
          <span>Secure Layer</span>
        </div>
      )}

      <footer className="fixed bottom-6 right-8 text-white/5 text-[7px] uppercase tracking-[0.5em] pointer-events-none font-medium">
        Precision Engine v3.0
      </footer>
    </div>
  );
};

export default App;

