const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<number | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  const formatNeuralResponse = (content: string) => {
    return content.replace(/\*\*/g, '').replace(/^#+\s+/gm, '').trim();
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim() || isLoading) return;

    const userQuery = query;
    setQuery('');
    setMessages(prev => [...prev, { role: 'user', content: userQuery }]);
    setIsLoading(true);
    setError(null);

    try {
      const stream = geminiService.streamSearch(userQuery);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          setMessages(prev => {
            const newMsgs = [...prev];
            newMsgs[newMsgs.length - 1] = { 
              ...newMsgs[newMsgs.length - 1], 
              content: chunk.text, 
              sources: chunk.sources 
            };
            return newMsgs;
          });
        }
      }
    } catch (error: any) {
      setError("Neutral connection interrupted. Uplink failover initiated.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleVoiceSearch = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopySuccess(index);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const editMessage = (text: string) => {
    setQuery(text);
  };

  const allSources = useMemo(() => {
    const sourcesMap = new Map();
    messages.forEach(msg => msg.sources?.forEach(s => sourcesMap.set(s.uri, s)));
    return Array.from(sourcesMap.values());
  }, [messages]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;

  return (
    <div className="relative h-screen w-full overflow-hidden flex flex-col items-center">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      {/* Header with improved Title Position */}
      <header className={`layout-transition fixed top-0 w-full z-[60] flex ${hasHistory ? 'h-20' : 'h-[38vh] items-end pb-12 justify-center'}`}>
        <SparkleTitle hasHistory={hasHistory} />
      </header>

      {/* Main Results Container */}
      <main 
        ref={scrollRef}
        className={`layout-transition w-full max-w-4xl px-8 overflow-y-auto overflow-x-hidden flex flex-col ${hasHistory ? 'pt-36 pb-48 opacity-100' : 'h-0 opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-12">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className="animate-result group/msg w-full flex flex-col"
              style={{ animationDelay: `${idx * 0.12}s` }}
            >
              <div className={`relative max-w-full border glass-card rounded-3xl px-12 py-10 text-slate-100 leading-relaxed transition-all duration-1000 hover:border-white/20 ${msg.role === 'user' ? 'border-white/10 bg-white/[0.015]' : 'border-white/[0.05]'}`}>
                {msg.role === 'assistant' && (
                  <div className="flex items-center gap-4 mb-8">
                    <div className="w-1.5 h-1.5 rounded-full bg-cyan-500/40 shadow-[0_0_10px_rgba(34,211,238,0.5)]" />
                    <span className="text-[10px] font-bold text-white/30 uppercase tracking-[0.5em]">Neural Insight</span>
                  </div>
                )}

                <div className="text-[16px] md:text-[18px] prose prose-invert max-w-none whitespace-pre-wrap font-light tracking-wide opacity-90 leading-[1.7]">
                  {msg.role === 'assistant' ? formatNeuralResponse(msg.content) : msg.content}
                </div>

                <div className={`absolute top-8 right-10 flex gap-5 transition-opacity duration-700 ${msg.role === 'user' ? 'opacity-30 group-hover/msg:opacity-100' : 'opacity-0 group-hover/msg:opacity-100'}`}>
                  {msg.role === 'user' ? (
                    <button onClick={() => editMessage(msg.content)} className="p-1.5 text-white/40 hover:text-cyan-400 transition-all hover:scale-110" title="Edit Search">
                      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                    </button>
                  ) : (
                    <button onClick={() => copyToClipboard(msg.content, idx)} className="p-1.5 text-white/40 hover:text-cyan-400 transition-all hover:scale-110" title="Copy Message">
                      {copySuccess === idx ? (
                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-green-400/70"><path d="M20 6 9 17l-5-5"/></svg>
                      ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
                      )}
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
          {isLoading && <CyberLoader />}
          {allSources.length > 0 && !isLoading && (
            <div className="animate-result" style={{ animationDelay: '0.4s' }}>
              <SourcesDisplay sources={allSources} />
            </div>
          )}
        </div>
      </main>

      {/* Professional Search Bar with High-Contrast Icons */}
      <div className={`layout-transition fixed left-0 right-0 px-6 flex justify-center z-[70] pointer-events-none ${hasHistory ? 'bottom-12' : 'top-1/2 -translate-y-1/2'}`}>
        <form 
          onSubmit={handleSearch} 
          className="w-full max-w-2xl pointer-events-auto"
        >
          <div className="search-container relative overflow-hidden rounded-full bg-white/[0.03] backdrop-blur-[50px] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.6)]">
            <input
              type="text" value={query} onChange={(e) => setQuery(e.target.value)}
              placeholder={isListening ? "Uplink Open..." : "Synthesize your request..."}
