              autoFocus
            />
            <div className="absolute right-8 top-1/2 -translate-y-1/2 flex items-center gap-5">
              <button 
                type="button" 
                onClick={toggleVoiceSearch} 
                className={`p-3.5 rounded-full transition-all duration-700 ${isListening ? 'text-red-400 bg-red-400/10' : 'text-white/60 hover:text-cyan-400 hover:bg-white/10'}`}
                title="Voice Synthesis"
