                className={`p-3.5 bg-white/10 text-white/80 rounded-full hover:bg-cyan-500/20 hover:text-cyan-300 transition-all duration-700 ${isLoading ? 'opacity-20' : 'hover:scale-105 shadow-lg'}`}
                title="Execute Query"
