const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<number | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.key === 's') {
        e.preventDefault();
        toggleVoiceSearch();
      }
      if (e.key === 'Escape') {
        setQuery('');
        setAttachedFile(null);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggleVoiceSearch]);

  const handleFileAttach = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      setAttachedFile({
        data: base64,
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim() || isLoading) return;

    const userQuery = query;
    const currentFile = attachedFile;
    setQuery('');
    setAttachedFile(null);
    setMessages(prev => [...prev, { role: 'user', content: userQuery }]);
    setIsLoading(true);
    setError(null);

    try {
      const stream = geminiService.streamSearch(userQuery, currentFile || undefined);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          setMessages(prev => {
            const newMsgs = [...prev];
            newMsgs[newMsgs.length - 1] = { 
              ...newMsgs[newMsgs.length - 1], 
              content: chunk.text, 
              sources: chunk.sources 
            };
            return newMsgs;
          });
        }
      }
    } catch (error: any) {
      setError("Neutral connection interrupted. Uplink failover initiated.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopySuccess(index);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const editMessage = (text: string) => {
    setQuery(text);
  };

  const allSources = useMemo(() => {
    const sourcesMap = new Map();
    messages.forEach(msg => msg.sources?.forEach(s => sourcesMap.set(s.uri, s)));
    return Array.from(sourcesMap.values());
  }, [messages]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;

  return (
    <div className="relative h-screen w-full overflow-hidden flex flex-col items-center">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex ${hasHistory ? 'h-20' : 'h-[38vh] items-end pb-12 justify-center'}`}>
        <SparkleTitle hasHistory={hasHistory} />
      </header>

      <main 
        ref={scrollRef}
        className={`layout-transition w-full max-w-4xl px-8 overflow-y-auto overflow-x-hidden flex flex-col ${hasHistory ? 'pt-36 pb-48 opacity-100' : 'h-0 opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-12">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className="animate-result group/msg w-full flex flex-col"
              style={{ animationDelay: `${idx * 0.12}s` }}
            >
              <div className={`relative max-w-full border glass-card rounded-3xl px-12 py-10 text-slate-100 leading-relaxed transition-all duration-1000 hover:border-white/20 ${msg.role === 'user' ? 'border-white/10 bg-white/[0.015]' : 'border-white/[0.05]'}`}>
                {msg.role === 'assistant' && (
                  <div className="flex items-center gap-4 mb-8">
                    <div className="w-2 h-2 rounded-full bg-cyan-400 shadow-[0_0_12px_rgba(34,211,238,0.8)]" />
                    <span className="text-[10px] font-bold text-cyan-400/90 uppercase tracking-[0.5em]">Neural Insight</span>
                  </div>
                )}

                <div className="text-[14px] md:text-[15.5px] max-w-none font-normal tracking-wide opacity-90 leading-[1.7]">
                  {msg.role === 'assistant' ? <FormattedContent content={msg.content} /> : msg.content}
                </div>

