                  </div>
                )}

                <div className="text-[14px] md:text-[15.5px] max-w-none font-normal tracking-wide opacity-90 leading-[1.7]">
                  {msg.role === 'assistant' ? <FormattedContent content={msg.content} /> : msg.content}
                </div>

                {/* Combined Action Bar for User and AI Messages */}
                <div className={`absolute top-8 right-10 flex gap-2 transition-opacity duration-700 opacity-0 group-hover/msg:opacity-100`}>
                  <button 
                    onClick={() => editMessage(msg.content)} 
                    className="action-button p-2"
                    title="Edit Query"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                    <span className="text-[9px] font-bold uppercase tracking-wider hidden md:inline">Edit</span>
                  </button>

                  <button 
                    onClick={() => copyToClipboard(msg.content, idx)} 
                    className="action-button p-2"
                    title="Copy Content"
                  >
                    {copySuccess === idx ? (
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-green-400"><path d="M20 6 9 17l-5-5"/></svg>
                    ) : (
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
                    )}
                    <span className="text-[9px] font-bold uppercase tracking-wider hidden md:inline">{copySuccess === idx ? 'Copied' : 'Copy'}</span>
                  </button>
                </div>
              </div>
            </div>
          ))}
          {isLoading && <CyberLoader />}
          {allSources.length > 0 && !isLoading && (
            <div className="animate-result" style={{ animationDelay: '0.4s' }}>
              <SourcesDisplay sources={allSources} />
            </div>
          )}
        </div>
      </main>

      <div className={`layout-transition fixed left-0 right-0 px-6 flex flex-col items-center justify-center z-[70] pointer-events-none ${hasHistory ? 'bottom-12' : 'top-1/2 -translate-y-1/2'}`}>

