              {attachedFile.mimeType.startsWith('image/') ? (
                <img src={`data:${attachedFile.mimeType};base64,${attachedFile.data}`} className="w-12 h-12 rounded-lg object-cover border border-white/20" alt="Attachment" />
              ) : (
                <div className="w-12 h-12 rounded-lg bg-cyan-500/20 flex items-center justify-center text-cyan-400 border border-cyan-500/40">
