const FormattedContent: React.FC<{ content: string }> = ({ content }) => {
  const renderTokens = useMemo(() => {
    const lines = content.split('\n');
    const elements: React.ReactNode[] = [];
    let currentCodeBlock: string[] | null = null;

    lines.forEach((line, i) => {
      // Code Block Logic
      if (line.trim().startsWith('```')) {
        if (currentCodeBlock) {
          elements.push(
            <pre key={`pre-${i}`} className="animate-fade-scale"><code>{currentCodeBlock.join('\n')}</code></pre>
          );
          currentCodeBlock = null;
        } else {
          currentCodeBlock = [];
        }
        return;
      }

      if (currentCodeBlock) {
        currentCodeBlock.push(line);
        return;
      }

      // Headers Logic
      if (line.startsWith('# ')) {
        elements.push(<h1 key={i} className="animate-fade-scale">{line.replace('# ', '')}</h1>);
      } else if (line.startsWith('## ')) {
        elements.push(<h2 key={i} className="animate-fade-scale">{line.replace('## ', '')}</h2>);
      } else if (line.startsWith('### ')) {
        elements.push(<h3 key={i} className="animate-fade-scale">{line.replace('### ', '')}</h3>);
      } 
      // List Logic
      else if (line.trim().startsWith('- ') || line.trim().startsWith('* ')) {
        const text = line.trim().substring(2);
        elements.push(
          <li key={i} className="animate-fade-scale" dangerouslySetInnerHTML={{ 
            __html: text.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>').replace(/`(.*?)`/g, '<code>$1</code>') 
          }} />
        );
      } 
      // Paragraph Logic
      else if (line.trim()) {
        const formattedLine = line
          .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
          .replace(/`(.*?)`/g, '<code>$1</code>');
        elements.push(<p key={i} className="animate-fade-scale" dangerouslySetInnerHTML={{ __html: formattedLine }} />);
      }
    });

    return elements;
  }, [content]);

  return <div className="md-content">{renderTokens}</div>;
};

