      <div className={`fixed left-0 right-0 px-4 sm:px-6 flex flex-col items-center z-[70] transition-all duration-700 ${hasHistory ? 'bottom-6 sm:bottom-10' : 'top-1/2 -translate-y-1/2'}`}>
