const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<number | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  // Handle outside clicks to close suggestions
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Debounced Suggestions
  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 200); // Snappier response
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if (!finalQuery || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);
    setAttachedFile(null);
    setMessages(prev => [...prev, { role: 'user', content: finalQuery }]);
    setIsLoading(true);
    setError(null);

    try {
      const stream = geminiService.streamSearch(finalQuery, attachedFile || undefined);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          setMessages(prev => {
            const newMsgs = [...prev];
            newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: chunk.text, sources: chunk.sources };
            return newMsgs;
          });
        }
      }
    } catch (err) {
      setError("Neural uplink failed. Environment interference detected.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopySuccess(index);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  useEffect(() => {
    if (scrollRef.current) {
      setTimeout(() => {
        scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
      }, 50);
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex ${hasHistory ? 'h-16 sm:h-20' : 'h-[35vh] sm:h-[40vh] items-end justify-center pb-8 sm:pb-12'}`}>
        <SparkleTitle hasHistory={hasHistory} />
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-4xl mx-auto px-4 sm:px-8 overflow-y-auto pt-24 sm:pt-40 pb-44 sm:pb-52 transition-opacity duration-700 ${hasHistory ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-8 sm:gap-14">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              <div className={`relative w-full border glass-card rounded-2xl sm:rounded-3xl p-6 sm:p-10 transition-all duration-500 hover:border-white/20 ${msg.role === 'user' ? 'border-white/10 bg-white/[0.02]' : 'border-white/[0.05]'}`}>
                {msg.role === 'assistant' && (
                  <div className="flex items-center gap-3 mb-8">
                    <div className="w-2.5 h-2.5 rounded-full bg-cyan-400 shadow-[0_0_12px_rgba(34,211,238,1)]" />
                    <span className="text-[10px] sm:text-[11px] font-bold text-cyan-400 uppercase tracking-[0.4em]">Neural Insight</span>
                  </div>
                )}

                <div className="text-sm sm:text-[16px] leading-relaxed opacity-90 font-light overflow-hidden transition-all duration-500">
                  {msg.role === 'assistant' ? (
                    <FormattedContent content={msg.content} />
                  ) : (
                    <div dangerouslySetInnerHTML={{ __html: formatLine(msg.content) }} />
                  )}
                </div>

                <div className="mt-8 sm:mt-0 sm:absolute sm:top-8 sm:right-10 opacity-80 sm:opacity-0 sm:group-hover/msg:opacity-100 transition-all duration-300">
                  <div className="action-pill">
                    <button 
                      onClick={() => { setQuery(msg.content); if(scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' }); }} 
                      className="action-pill-item active-cyan" title="Edit Content"
                    >
                      <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                    </button>

                    <div className="w-px h-4 bg-white/5 mx-1" />

                    <button 
                      onClick={() => copyToClipboard(msg.content, idx)} 
                      className="action-pill-item active-cyan" title="Copy Content"
                    >
                      {copySuccess === idx ? (
                        <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="text-green-400"><path d="M20 6 9 17l-5-5"/></svg>
                      ) : (
                        <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="8" height="4" x="8" y="2" rx="1" ry="1"/><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/></svg>
                      )}
                    </button>
                  </div>
                </div>
              </div>
              {msg.sources && msg.sources.length > 0 && <SourcesDisplay sources={msg.sources} />}
            </div>
          ))}
          {isLoading && <CyberLoader />}
        </div>
      </main>

      <div 
        className={`fixed left-0 right-0 px-4 sm:px-6 flex flex-col items-center z-[70] transition-all duration-700 ${
          hasHistory 
            ? 'bottom-6 sm:bottom-10' 
            : 'top-[45vh]' // Anchor to a fixed top position to prevent upward shift when suggestions appear
        }`}
      >
        <div className="w-full max-w-3xl relative flex flex-col items-center">
          {attachedFile && (
            <div className="w-full max-w-xs mb-4 animate-result self-start ml-0 sm:ml-8">
              <div className="bg-black/60 backdrop-blur-2xl border border-cyan-500/40 rounded-2xl p-3 flex items-center gap-4 shadow-2xl">
                <div className="w-12 h-12 rounded-xl bg-cyan-500/10 flex items-center justify-center text-cyan-400 border border-cyan-500/20">
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
                </div>
