export interface SearchResult {
  text: string;
  sources: Array<{
    title: string;
    uri: string;
  }>;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
  images?: string[]; // Array of base64 images
  sources?: Array<{ title: string; uri: string }>;
  relatedQueries?: string[]; // Follow-up suggestions
}

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { SearchResult } from "../types";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze the partial search query: "${input}". 
        Predict the user's intent and provide 4 distinct, high-quality, and specific search completions. 
        Focus on trending topics, technical queries, or common knowledge. 
        Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch (error) {
      console.error("Suggestion Error:", error);
      return [];
    }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on the search query "${query}" and the following context: "${context.substring(0, 500)}", generate 3 short, engaging follow-up questions that the user might want to ask next. Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  }

  async generateTopicImage(query: string): Promise<string | undefined> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `A futuristic, professional, and cinematic conceptual visualization of: "${query}". Style: Ultra-high definition, dark cyan and obsidian tones, sleek technology aesthetic, depth of field.` }],
        },
        config: {
          imageConfig: { aspectRatio: "16:9" }
        },
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    } catch (error) {
      console.error("Image Generation Error:", error);
    }
    return undefined;
  }

  async performSearch(query: string, file?: AttachedFile): Promise<SearchResult> {
    try {
      const parts: any[] = [{ text: query }];
      if (file) {
        parts.push({
          inlineData: {
            data: file.data,
            mimeType: file.mimeType
          }
        });
      }

      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: { parts },
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "I couldn't find an answer to that.";
      const candidates = response.candidates || [];
      const groundingChunks = (candidates[0]?.groundingMetadata as any)?.groundingChunks || [];
      const sources: Array<{ title: string; uri: string }> = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web?.title || "Source",
          uri: chunk.web?.uri || ""
        }));

      const uniqueSources: Array<{ title: string; uri: string }> = Array.from(
        new Map(sources.map(s => [s.uri, s])).values()
      );

      return {
        text,
        sources: uniqueSources
      };
    } catch (error) {
      console.error("Gemini Search Error:", error);
      throw error;
    }
  }

  async *streamSearch(query: string, file?: AttachedFile) {
    try {
      const parts: any[] = [{ text: query }];
      if (file) {
        parts.push({
          inlineData: {
            data: file.data,
            mimeType: file.mimeType
          }
        });
      }

      const responseStream = await this.ai.models.generateContentStream({
        model: "gemini-3-flash-preview",
        contents: { parts },
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        yield {
          text: c.text || "",
          done: false,
          sources: [] as Array<{ title: string; uri: string }>
        };
      }

      const fullResponse = await this.performSearch(query, file);
      yield {
        ...fullResponse,
        done: true
      };
    } catch (error) {
      console.error("Gemini Stream Error:", error);
      throw error;
    }
  }
}

