                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/></svg>
                </button>
                <button type="submit" disabled={isLoading} className="p-3.5 bg-cyan-500 rounded-full text-black hover:bg-cyan-400 hover:scale-105 transition-all shadow-lg active:scale-95 disabled:opacity-50">
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                </button>
              </div>
            </div>

            {/* Predictive Suggestions Overlay */}
            {showSuggestions && (
              <div ref={suggestionRef} className="absolute top-full left-4 right-4 mt-4 bg-[#111115]/95 backdrop-blur-3xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl z-[80] origin-top animate-result">
                <div className="p-2 flex flex-col">
                  {suggestions.map((suggestion, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSearch(undefined, suggestion)}
                      className="w-full text-left px-8 py-5 text-sm text-white/50 hover:text-cyan-400 hover:bg-white/[0.03] transition-all flex items-center justify-between group"
                    >
                      <div className="flex items-center gap-4">
                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-white/10 group-hover:text-cyan-400 transition-colors"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                        <span className="font-light">{suggestion}</span>
                      </div>
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>
          {attachedFile && (
            <div className="mt-4 flex items-center gap-3 px-4 py-2 bg-cyan-500/10 border border-cyan-500/20 rounded-full animate-result">
              <span className="text-[9px] font-bold text-cyan-400 uppercase tracking-widest">Document Linked</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 hover:text-white"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex justify-center gap-12 sm:gap-24 text-[10px] uppercase tracking-[1em] text-white/10 pointer-events-none select-none font-bold">
          <span>Global Context</span>
          <span>Verified Insight</span>
        </div>
      )}
    </div>
  );
};

