              <input
                type="text" value={query} 
                onChange={(e) => setQuery(e.target.value)}
                placeholder={isListening ? "Uplink Open..." : "Seek Knowledge..."}
                onFocus={() => query.length >= 2 && setShowSuggestions(true)}
                className="w-full bg-transparent pl-16 pr-40 py-7 text-white placeholder-white/10 focus:outline-none text-lg font-light tracking-tight selection:bg-cyan-500/30 antialiased"
