                </button>
              </div>
            </div>

            {/* Predictive Suggestions - Glass Overlay */}
            {showSuggestions && suggestions.length > 0 && (
              <div ref={suggestionRef} className="absolute top-full left-5 right-5 mt-5 bg-black/70 backdrop-blur-[50px] border border-white/10 rounded-3xl overflow-hidden shadow-[0_50px_150px_rgba(0,0,0,1)] z-[80] origin-top animate-result ring-1 ring-white/5">
                <div className="p-2 flex flex-col">
                  {suggestions.map((suggestion, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSearch(undefined, suggestion)}
                      className="w-full text-left px-8 py-5 text-[14px] text-white/40 hover:text-cyan-400 hover:bg-white/[0.04] rounded-2xl transition-all flex items-center justify-between group"
                    >
                      <div className="flex items-center gap-5">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-white/10 group-hover:text-cyan-400 transition-colors"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                        <span className="font-light tracking-tight">{suggestion}</span>
                      </div>
                      <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" className="opacity-0 group-hover:opacity-100 -translate-x-3 group-hover:translate-x-0 transition-all"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {/* Attached File Indicator */}
          {attachedFile && (
            <div className="mt-5 flex items-center gap-3 px-5 py-2.5 bg-cyan-500/10 border border-cyan-500/20 rounded-full animate-result shadow-2xl backdrop-blur-xl">
              <span className="text-[10px] font-bold text-cyan-400 uppercase tracking-[0.2em] flex items-center gap-2">
                <div className="w-1.5 h-1.5 rounded-full bg-cyan-400 animate-pulse" />
                Media Payload Locked
              </span>
              <div className="w-px h-3 bg-cyan-500/20 mx-1" />
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 hover:text-white transition-colors">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12"/></svg>
              </button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex justify-center gap-12 sm:gap-24 text-[10px] uppercase tracking-[1.2em] text-white/5 pointer-events-none select-none font-black antialiased">
          <span>Hyperlink Synthesis</span>
          <span>Verified Protocol</span>
        </div>
      )}
    </div>
  );
};

