const formatLine = (line: string) => {
  return line
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') 
    .replace(/\*\*/g, '') 
    .replace(/`(.*?)`/g, '<code>$1</code>');
};

const FormattedContent: React.FC<{ content: string }> = ({ content }) => {
  const renderTokens = useMemo(() => {
    const lines = content.split('\n');
    const elements: React.ReactNode[] = [];
    let currentCodeBlock: string[] | null = null;

    lines.forEach((line, i) => {
      if (line.trim().startsWith('```')) {
        if (currentCodeBlock) {
          elements.push(
            <pre key={`pre-${i}`} className="animate-fade-scale"><code>{currentCodeBlock.join('\n')}</code></pre>
          );
          currentCodeBlock = null;
        } else {
          currentCodeBlock = [];
        }
        return;
      }

      if (currentCodeBlock) {
        currentCodeBlock.push(line);
        return;
      }

      if (line.startsWith('# ')) {
        elements.push(<h1 key={i} className="animate-fade-scale">{formatLine(line.replace('# ', ''))}</h1>);
      } else if (line.startsWith('## ')) {
        elements.push(<h2 key={i} className="animate-fade-scale">{formatLine(line.replace('## ', ''))}</h2>);
      } else if (line.startsWith('### ')) {
        elements.push(<h3 key={i} className="animate-fade-scale">{formatLine(line.replace('### ', ''))}</h3>);
      } 
      else if (line.trim().startsWith('- ') || line.trim().startsWith('* ')) {
        const text = line.trim().substring(2);
        elements.push(
          <li key={i} className="animate-fade-scale" dangerouslySetInnerHTML={{ 
            __html: formatLine(text)
          }} />
        );
      } 
      else if (line.trim()) {
        elements.push(<p key={i} className="animate-fade-scale" dangerouslySetInnerHTML={{ __html: formatLine(line) }} />);
      }
    });

    return elements;
  }, [content]);

  return <div className="md-content">{renderTokens}</div>;
};

type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze attached file" }]);
    setIsLoading(true);
    setError(null);

    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.generateTopicImage(finalQuery || "Abstract data visualization");
      const stream = geminiService.streamSearch(finalQuery || "Please analyze the content provided.", currentFile || undefined);
      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          const finalImage = await imageGenPromise;
          const related = await geminiService.generateRelatedQueries(finalQuery, chunk.text);
          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              content: chunk.text, 
              sources: chunk.sources,
              images: finalImage ? [finalImage] : [],
              relatedQueries: related
            };
            return newMsgs;
          });
          setActiveTabs(prev => ({ ...prev, [messages.length + 1]: 'synthesis' }));
          setIsLoading(false);
        }
      }
    } catch (err) {
      setError("Neural uplink failed. Environment interference detected.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      setTimeout(() => {
        scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
      }, 100);
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;
  const canSubmit = query.trim().length > 0 || attachedFile !== null;

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden font-sans selection:bg-cyan-500/30">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-6 ${hasHistory ? 'h-16 border-b border-white/[0.05] bg-black/40 backdrop-blur-md' : 'h-[35vh] sm:h-[40vh] items-end justify-center pb-8 sm:pb-12'}`}>
        <SparkleTitle hasHistory={hasHistory} />
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-[880px] mx-auto px-4 sm:px-6 overflow-y-auto pt-24 sm:pt-32 pb-64 transition-opacity duration-700 ${hasHistory ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-14">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              {msg.role === 'user' ? (
                <div className="flex items-center gap-6 py-4 px-4">
                  <div className="w-10 h-10 rounded-full bg-white/[0.05] border border-white/10 flex items-center justify-center text-[11px] font-bold text-white/30 shrink-0 shadow-2xl">U</div>
                  <h2 className="text-xl sm:text-2xl font-light text-white/90 tracking-tight leading-relaxed" dangerouslySetInnerHTML={{ __html: formatLine(msg.content) }} />
                </div>
              ) : (
                <div className="flex flex-col border border-white/[0.08] bg-white/[0.02] backdrop-blur-3xl rounded-[2.5rem] overflow-hidden shadow-[0_30px_100px_rgba(0,0,0,0.5)] transition-all hover:border-white/10 ring-1 ring-white/5">

                  {/* Thinking status appears at top of response */}
                  {idx === messages.length - 1 && isLoading && <ThinkingIndicator />}

                  {/* Perplexity Style Content Tabs */}
                  <div className="flex items-center px-7 py-5 border-b border-white/[0.04] bg-white/[0.01]">
                    <div className="flex bg-white/[0.05] p-1 rounded-full gap-1 border border-white/5 shadow-inner">
                      {[
                        { id: 'synthesis', label: 'Synthesis' },
                        { id: 'media', label: 'Media' },
                        { id: 'references', label: 'References' }
                      ].map((tab) => (
                        <button
                          key={tab.id}
                          onClick={() => setActiveTabs(prev => ({ ...prev, [idx]: tab.id as ViewMode }))}
                          className={`px-6 py-2 rounded-full text-[10px] font-bold uppercase tracking-[0.2em] transition-all duration-300 ${
                            (activeTabs[idx] || 'synthesis') === tab.id 
                            ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/20 shadow-[0_0_20px_rgba(34,211,238,0.1)]' 
                            : 'text-white/20 hover:text-white/60 hover:bg-white/5'
                          }`}
                        >
                          {tab.label}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Tab Body */}
                  <div className="p-10 sm:p-12 min-h-[280px]">
                    {(activeTabs[idx] || 'synthesis') === 'synthesis' && (
                      <div className="animate-fade-scale">
                        <div className="text-sm sm:text-[16px] leading-[1.9] opacity-90 font-light md-content max-w-none antialiased">
                          <FormattedContent content={msg.content} />
                        </div>
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'media' && (
                      <div className="animate-fade-scale grid grid-cols-1 gap-8">
                        {msg.images && msg.images.length > 0 ? (
                          msg.images.map((img, i) => (
                            <div key={i} className="group/img relative rounded-3xl overflow-hidden border border-white/5 shadow-2xl aspect-video bg-black/80 ring-1 ring-white/5">
                              <img src={img} alt="Generated Asset" className="w-full h-full object-cover transition-transform duration-[2000ms] group-hover/img:scale-105" />
                            </div>
                          ))
                        ) : (
                          <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-white/5 rounded-3xl opacity-10">
                            <span className="text-[11px] uppercase tracking-[0.5em]">No Visual Metadata Found</span>
                          </div>
                        )}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'references' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {msg.sources && msg.sources.length > 0 ? (
                          msg.sources.map((source, i) => (
                            <a 
                              key={i} href={source.uri} target="_blank" rel="noopener noreferrer"
                              className="group/link flex items-center gap-5 p-6 rounded-3xl border border-white/5 bg-white/[0.03] hover:bg-cyan-500/5 hover:border-cyan-500/30 transition-all shadow-lg ring-1 ring-white/5"
                            >
                              <div className="w-8 h-8 rounded-xl bg-white/5 flex items-center justify-center text-[11px] font-mono text-white/20 border border-white/5 group-hover/link:bg-cyan-500 group-hover/link:text-black transition-all">
                                {i + 1}
