import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { SearchResult } from "../types";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // API key is managed exclusively via process.env.API_KEY per infrastructure protocol.
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  private async withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
    try {
      return await fn();
    } catch (error: any) {
      const errorStr = JSON.stringify(error).toUpperCase();
      const isQuotaError = 
        error?.message?.includes('429') || 
        error?.status === 'RESOURCE_EXHAUSTED' || 
        errorStr.includes('RESOURCE_EXHAUSTED') ||
        errorStr.includes('QUOTA_EXCEEDED');

      if (isQuotaError && retries > 0) {
        // Log locally for debugging, but don't disrupt the user
        console.warn(`Neural uplink saturated, retrying in ${delay}ms...`);
        await sleep(delay);
        return this.withRetry(fn, retries - 1, delay * 2);
      }

      if (isQuotaError) {
        throw new Error('QUOTA_EXCEEDED');
      }

      throw error;
    }
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      // Use lite model to preserve primary search quota and reduce latency
      return await this.withRetry(async () => {
        const response = await this.ai.models.generateContent({
          model: "gemini-flash-lite-latest",
          contents: `Query: "${input}". Provide 4 completions. Return ONLY a JSON array of strings.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          }
        });
        return JSON.parse(response.text || "[]");
      }, 1, 300); // Fewer retries for latency-sensitive features
    } catch {
      // Return empty instead of error for typing suggestions
      return [];
    }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      return await this.withRetry(async () => {
        const response = await this.ai.models.generateContent({
          model: "gemini-flash-lite-latest",
          contents: `Context: "${context.substring(0, 300)}". Generate 3 follow-up questions for query "${query}". Return ONLY a JSON array.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          }
        });
        return JSON.parse(response.text || "[]");
      }, 1, 500);
    } catch {
      return [];
    }
  }

  async generateTopicImage(query: string): Promise<string | undefined> {
    try {
      return await this.withRetry(async () => {
        const response = await this.ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [{ text: `Conceptual visual rendering: "${query}". Futuristic tech, cyan and obsidian palette.` }],
          },
          config: {
            imageConfig: { aspectRatio: "16:9" }
          },
        });

        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
        return undefined;
      }, 1, 1000);
    } catch {
      return undefined;
    }
  }

  async performSearch(query: string, file?: AttachedFile): Promise<SearchResult> {
    return this.withRetry(async () => {
      const parts: any[] = [{ text: query }];
      if (file) {
        parts.push({
          inlineData: { data: file.data, mimeType: file.mimeType }
        });
      }

      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: { parts },
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "I was unable to synthesize a response from the current data stream.";
      const candidates = response.candidates || [];
      const groundingChunks = (candidates[0]?.groundingMetadata as any)?.groundingChunks || [];
      const sources: Array<{ title: string; uri: string }> = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          title: chunk.web?.title || "Reference",
          uri: chunk.web?.uri || ""
        }));

      // Return unique sources only
      return {
        text,
        sources: Array.from(new Map(sources.map(s => [s.uri, s])).values())
      };
    });
  }

  async *streamSearch(query: string, file?: AttachedFile) {
    try {
      const parts: any[] = [{ text: query }];
      if (file) {
        parts.push({
          inlineData: { data: file.data, mimeType: file.mimeType }
        });
      }

      const responseStream = await this.ai.models.generateContentStream({
        model: "gemini-3-flash-preview",
        contents: { parts },
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        yield {
          text: c.text || "",
          done: false,
          sources: [] as Array<{ title: string; uri: string }>
        };
      }

      const fullResponse = await this.performSearch(query, file);
      yield {
        ...fullResponse,
        done: true
      };
    } catch (error: any) {
      const errorStr = JSON.stringify(error).toUpperCase();
      if (error?.message?.includes('429') || error?.status === 'RESOURCE_EXHAUSTED' || errorStr.includes('QUOTA_EXCEEDED')) {
        throw new Error('QUOTA_EXCEEDED');
      }
      throw error;
    }
  }
}

