                          <FormattedContent content={msg.content} />
                        </div>
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'media' && (
                      <div className="animate-fade-scale grid grid-cols-1 gap-10">
                        {msg.images && msg.images.length > 0 ? (
                          msg.images.map((img, i) => (
                            <div key={i} className="group/img relative rounded-[2.5rem] overflow-hidden border border-white/5 shadow-2xl aspect-video bg-black/80 ring-1 ring-white/10">
                              <img src={img} alt="Synthesis Visualization" className="w-full h-full object-cover transition-transform duration-[3s] group-hover/img:scale-110" />
                              <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover/img:opacity-100 transition-opacity duration-700 flex items-end p-10">
                                <p className="text-[11px] text-cyan-400/80 font-bold uppercase tracking-[0.5em]">Neural Frame Generation</p>
                              </div>
                            </div>
                          ))
                        ) : (
                          <div className="h-72 flex flex-col items-center justify-center border-2 border-dashed border-white/5 rounded-[2.5rem] opacity-20">
                            <span className="text-[11px] uppercase tracking-[0.6em]">No Visual Metadata Synthesized</span>
                          </div>
                        )}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'references' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-5">
                        {msg.sources && msg.sources.length > 0 ? (
                          msg.sources.map((source, i) => (
