      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-6 ${hasHistory ? 'h-16 border-b border-white/[0.05] bg-black/40 backdrop-blur-md' : 'h-[35vh] sm:h-[40vh] items-end justify-center pb-12'}`}>
        <SparkleTitle hasHistory={hasHistory} />
