                  <div className="w-11 h-11 rounded-2xl bg-white/[0.05] border border-white/10 flex items-center justify-center text-[11px] font-black text-white/40 shrink-0 shadow-2xl rotate-3">U</div>
                  <h2 className="text-2xl sm:text-3xl font-light text-white tracking-tight leading-tight" dangerouslySetInnerHTML={{ __html: formatLine(msg.content) }} />
                </div>
              ) : (
                <div className="flex flex-col border border-white/[0.08] bg-white/[0.02] backdrop-blur-[50px] rounded-[2.5rem] overflow-hidden shadow-[0_40px_120px_rgba(0,0,0,0.6)] transition-all hover:border-white/10 ring-1 ring-white/5">

                  {idx === messages.length - 1 && isLoading && <ThinkingIndicator status={status} />}

                  <div className="flex items-center px-8 py-5 border-b border-white/[0.03] bg-white/[0.01]">
                    <div className="flex bg-white/[0.04] p-1 rounded-full gap-1 border border-white/5">
