const formatLine = (line: string) => {
  return line
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') 
    .replace(/\*\*/g, '') 
    .replace(/`(.*?)`/g, '<code>$1</code>');
};

const FormattedContent: React.FC<{ content: string }> = ({ content }) => {
  const renderTokens = useMemo(() => {
    const lines = content.split('\n');
    const elements: React.ReactNode[] = [];
    let currentCodeBlock: string[] | null = null;

    lines.forEach((line, i) => {
      if (line.trim().startsWith('```')) {
        if (currentCodeBlock) {
          elements.push(
            <pre key={`pre-${i}`} className="animate-result" style={{ animationDelay: `${i * 0.05}s` }}><code>{currentCodeBlock.join('\n')}</code></pre>
          );
          currentCodeBlock = null;
        } else {
          currentCodeBlock = [];
        }
        return;
      }

      if (currentCodeBlock) {
        currentCodeBlock.push(line);
        return;
      }

      const style = { animationDelay: `${i * 0.05}s` };

      if (line.startsWith('# ')) {
        elements.push(<h1 key={i} className="animate-result" style={style}>{formatLine(line.replace('# ', ''))}</h1>);
      } else if (line.startsWith('## ')) {
        elements.push(<h2 key={i} className="animate-result" style={style}>{formatLine(line.replace('## ', ''))}</h2>);
      } else if (line.startsWith('### ')) {
        elements.push(<h3 key={i} className="animate-result" style={style}>{formatLine(line.replace('### ', ''))}</h3>);
      } 
      else if (line.trim().startsWith('- ') || line.trim().startsWith('* ')) {
        const text = line.trim().substring(2);
        elements.push(
          <li key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ 
            __html: formatLine(text)
          }} />
        );
      } 
      else if (line.trim()) {
        elements.push(<p key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: formatLine(line) }} />);
      }
    });

    return elements;
  }, [content]);

  return <div className="md-content">{renderTokens}</div>;
};

type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [status, setStatus] = useState('Thinking...');
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze Payload" }]);
    setIsLoading(true);
    setStatus('Initializing Uplink...');
    setError(null);

    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.generateTopicImage(finalQuery || "Conceptual visualization");

      // Stage 1: LangSearch
      setStatus('Accessing Global Data...');
      const stream = geminiService.streamSearch(finalQuery || "Analyze search context.", currentFile || undefined);

      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          setStatus('Neural Synthesis...');
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          const finalImage = await imageGenPromise;
          const related = await geminiService.generateRelatedQueries(finalQuery, accumulatedText);
          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              sources: chunk.sources,
              images: finalImage ? [finalImage] : [],
              relatedQueries: related
            };
            return newMsgs;
          });
          setActiveTabs(prev => ({ ...prev, [messages.length + 1]: 'synthesis' }));
          setIsLoading(false);
        }
      }
    } catch (err: any) {
      if (err.message === 'QUOTA_EXCEEDED') {
        setError("Neural core saturated. Global limits reached. Please stand by.");
      } else {
        setError("Uplink failed. Local interference detected.");
      }
      setMessages(prev => {
        if (prev.length > 0 && prev[prev.length - 1].role === 'assistant' && !prev[prev.length - 1].content) {
          return prev.slice(0, -1);
        }
        return prev;
      });
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      setTimeout(() => {
        scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
      }, 100);
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;
  const canSubmit = query.trim().length > 0 || attachedFile !== null;

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden font-sans selection:bg-cyan-500/20">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-8 ${hasHistory ? 'h-20 border-b border-white/[0.05] bg-black/40 backdrop-blur-2xl' : 'h-[38vh] items-end justify-center pb-12'}`}>
        <SparkleTitle hasHistory={hasHistory} isLoading={isLoading} />
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-[960px] mx-auto px-6 overflow-y-auto pt-28 sm:pt-40 pb-64 transition-all duration-1000 ${hasHistory ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-20">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              {msg.role === 'user' ? (
                <div className="flex items-center gap-8 py-8 px-6">
                  <div className="w-12 h-12 rounded-3xl bg-white/[0.03] border border-white/10 flex items-center justify-center text-[11px] font-black text-white/30 shrink-0 shadow-2xl rotate-[15deg] group-hover/msg:rotate-0 transition-transform">ID</div>
                  <h2 className="text-2xl sm:text-4xl font-extralight text-white/90 tracking-tight leading-snug" dangerouslySetInnerHTML={{ __html: formatLine(msg.content) }} />
                </div>
              ) : (
                <div className="flex flex-col border border-white/[0.06] bg-white/[0.01] backdrop-blur-[60px] rounded-[3rem] overflow-hidden shadow-[0_60px_140px_rgba(0,0,0,0.7)] transition-all hover:border-white/[0.12] group/card ring-1 ring-white/5">

                  {idx === messages.length - 1 && isLoading && <ThinkingIndicator status={status} />}

                  <div className="flex items-center px-10 py-6 border-b border-white/[0.03] bg-white/[0.02]">
                    <div className="flex bg-white/[0.03] p-1.5 rounded-full gap-1 border border-white/5 shadow-inner">
                      {[
                        { id: 'synthesis', label: 'Synthesis' },
                        { id: 'media', label: 'Media' },
                        { id: 'references', label: 'Sources' }
                      ].map((tab) => (
                        <button
                          key={tab.id}
                          onClick={() => setActiveTabs(prev => ({ ...prev, [idx]: tab.id as ViewMode }))}
                          className={`px-8 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.3em] transition-all duration-700 ${
                            (activeTabs[idx] || 'synthesis') === tab.id 
                            ? 'bg-cyan-500/20 text-cyan-300 border border-cyan-500/30 shadow-[0_0_40px_rgba(34,211,238,0.1)]' 
                            : 'text-white/20 hover:text-white/60 hover:bg-white/5'
                          }`}
                        >
                          {tab.label}
                        </button>
                      ))}
                    </div>
                    <div className="flex-1" />
                    <div className="flex items-center gap-4 opacity-30">
                      <div className="w-1 h-1 rounded-full bg-cyan-400 animate-pulse" />
                      <div className="text-[9px] font-mono text-cyan-400 uppercase tracking-[0.3em]">L-SEARCH.001</div>
                    </div>
                  </div>

                  <div className="p-12 sm:p-16 min-h-[350px]">
                    {(activeTabs[idx] || 'synthesis') === 'synthesis' && (
                      <div className="animate-fade-scale">
                        <div className="text-[16px] sm:text-[18px] leading-[1.8] opacity-90 font-light md-content max-w-none selection:bg-cyan-500/30 antialiased">
                          <FormattedContent content={msg.content} />
                        </div>
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'media' && (
                      <div className="animate-fade-scale grid grid-cols-1 gap-12">
                        {msg.images && msg.images.length > 0 ? (
                          msg.images.map((img, i) => (
                            <div key={i} className="group/img relative rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl aspect-video bg-black/90 ring-1 ring-white/10">
                              <img src={img} alt="Synthesis Visual" className="w-full h-full object-cover transition-transform duration-[6s] group-hover/img:scale-105" />
                              <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-transparent to-transparent opacity-0 group-hover/img:opacity-100 transition-opacity duration-1000 flex items-end p-12">
                                <div>
                                  <p className="text-[10px] text-cyan-400 font-black uppercase tracking-[0.6em] mb-2">Neural Frame</p>
                                  <p className="text-[13px] text-white/40 font-light italic">Conceptual synthesis generated via Spark Vision Engine</p>
                                </div>
                              </div>
                            </div>
                          ))
                        ) : (
                          <div className="h-80 flex flex-col items-center justify-center border border-dashed border-white/5 rounded-[3rem] opacity-20">
                            <span className="text-[10px] uppercase tracking-[0.8em]">Metadata Viz Pipeline Idle</span>
                          </div>
                        )}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'references' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-6">
                        {msg.sources && msg.sources.length > 0 ? (
                          msg.sources.map((source, i) => (
                            <a 
                              key={i} href={source.uri} target="_blank" rel="noopener noreferrer"
                              className="group/link flex flex-col gap-4 p-8 rounded-[2.5rem] border border-white/5 bg-white/[0.02] hover:bg-cyan-500/5 hover:border-cyan-500/30 transition-all shadow-xl ring-1 ring-white/5"
                            >
                              <div className="flex items-center justify-between">
                                <div className="w-9 h-9 rounded-2xl bg-white/5 flex items-center justify-center text-[11px] font-mono text-cyan-400/40 border border-white/10 group-hover/link:bg-cyan-400 group-hover/link:text-black transition-all">
                                  {String(i + 1).padStart(2, '0')}
                                </div>
                                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-white/10 group-hover/link:translate-x-1 group-hover/link:-translate-y-1 transition-all"><path d="M7 17L17 7M17 7H7M17 7V17"/></svg>
                              </div>
                              <div className="flex-1">
                                <h4 className="text-[14px] font-bold text-white/70 group-hover/link:text-white transition-colors">{source.title}</h4>
                                <p className="text-[9px] text-cyan-400/30 font-mono mt-2 uppercase tracking-[0.2em]">{new URL(source.uri).hostname}</p>
                              </div>
                            </a>
                          ))
                        ) : (
                          <div className="h-64 col-span-2 flex items-center justify-center opacity-10 uppercase tracking-[2em] text-[9px] font-black">Link Table Null</div>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}

          {!isLoading && messages.length > 0 && (
            <div className="animate-result flex flex-col gap-10 py-16">
              <div className="flex items-center gap-8">
                <div className="h-px flex-1 bg-gradient-to-r from-transparent to-white/5" />
                <span className="text-[10px] font-black text-white/15 uppercase tracking-[1.5em] whitespace-nowrap">Discovery Path</span>
                <div className="h-px flex-1 bg-gradient-to-l from-transparent to-white/5" />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                {(messages[messages.length-1].relatedQueries || [
                  "Technical deep-dive",
                  "Historical context",
                  "Future projections"
                ]).map((text, i) => (
                  <button
                    key={i}
                    onClick={() => handleSearch(undefined, text)}
                    className="flex flex-col items-start p-10 rounded-[2.8rem] border border-white/5 bg-white/[0.01] hover:bg-cyan-500/[0.03] hover:border-cyan-500/40 hover:shadow-[0_40px_100px_rgba(0,0,0,0.5)] transition-all text-left group/path relative overflow-hidden"
                  >
                    <div className="absolute top-0 right-0 p-4 opacity-5 group-hover/path:opacity-20 transition-opacity">
                      <svg width="60" height="60" viewBox="0 0 100 100" fill="none" stroke="currentColor" strokeWidth="1"><circle cx="50" cy="50" r="45"/><path d="M50 20v60M20 50h60"/></svg>
                    </div>
                    <div className="w-12 h-12 rounded-full bg-cyan-500/10 flex items-center justify-center text-cyan-400 mb-8 group-hover/path:scale-110 group-hover/path:rotate-[15deg] transition-all duration-700">
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 6v12a3 3 0 1 0 3-3H6a3 3 0 1 0 3 3V6a3 3 0 1 0-3 3h12a3 3 0 1 0-3-3z"/></svg>
                    </div>
                    <span className="text-[14px] leading-relaxed text-white/40 group-hover/path:text-white transition-colors font-light antialiased">{text}</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      <div 
        className={`fixed left-0 right-0 px-6 flex flex-col items-center z-[70] transition-all duration-[1200ms] cubic-bezier(0.22, 1, 0.36, 1) ${
          hasHistory ? 'bottom-16' : 'top-[50vh] -translate-y-1/2'
        }`}
      >
        <div className="w-full max-w-3xl relative flex flex-col items-center">
          <form onSubmit={handleSearch} className="w-full relative group">
            <div className={`relative overflow-hidden rounded-[3.2rem] bg-white/[0.03] backdrop-blur-[50px] border border-white/10 shadow-[0_60px_200px_rgba(0,0,0,0.9)] transition-all duration-1000 focus-within:border-cyan-500/60 focus-within:shadow-[0_0_100px_rgba(34,211,238,0.2)] focus-within:bg-white/[0.06] ring-1 ring-white/10`}>

              <button 
                type="button" 
                onClick={() => fileInputRef.current?.click()}
                className={`absolute left-10 top-1/2 -translate-y-1/2 p-4 transition-all duration-500 rounded-2xl ${attachedFile ? 'bg-cyan-500 text-black shadow-[0_0_25px_rgba(34,211,238,0.6)]' : 'text-white/15 hover:text-cyan-400 hover:bg-white/5'}`}
              >
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l8.57-8.57a4 4 0 1 1 5.66 5.66l-8.59 8.51a2 2 0 0 1-2.83-2.83l8.49-8.48" />
                </svg>
              </button>

              <input type="file" ref={fileInputRef} className="hidden" onChange={async (e) => {
                const file = e.target.files?.[0];
                if (file) {
                  const reader = new FileReader();
                  reader.onloadend = () => setAttachedFile({ data: (reader.result as string).split(',')[1], mimeType: file.type });
                  reader.readAsDataURL(file);
                }
              }} />

              <input
                type="text" value={query} 
                onChange={(e) => setQuery(e.target.value)}
                placeholder={isListening ? "Listening..." : "Request intelligence synthesis..."}
                onFocus={() => query.length >= 2 && setShowSuggestions(true)}
                className="w-full bg-transparent pl-24 pr-48 py-9 text-white placeholder-white/10 focus:outline-none text-xl font-extralight tracking-tight selection:bg-cyan-500/40 antialiased"
                autoFocus
              />

              <div className="absolute right-8 top-1/2 -translate-y-1/2 flex items-center gap-4">
                <button type="button" onClick={toggleVoiceSearch} className={`p-5 rounded-full transition-all duration-700 ${isListening ? 'bg-red-500/60 text-white shadow-[0_0_30px_rgba(239,68,68,0.5)] animate-pulse' : 'text-white/10 hover:text-cyan-400 hover:bg-white/5'}`}>
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/></svg>
                </button>

                <button 
                  type="submit" 
                  disabled={isLoading || !canSubmit} 
                  className={`p-5 rounded-full transition-all duration-1000 shadow-2xl active:scale-95 flex items-center justify-center ${
                    canSubmit 
                    ? 'bg-cyan-500 text-black scale-100 shadow-[0_0_50px_rgba(34,211,238,0.5)] rotate-0' 
                    : 'bg-white/5 text-white/10 scale-90 opacity-20 grayscale rotate-45'
                  }`}
                >
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                </button>
              </div>
            </div>

            {showSuggestions && suggestions.length > 0 && (
              <div ref={suggestionRef} className="absolute top-full left-10 right-10 mt-8 bg-black/90 backdrop-blur-[80px] border border-white/10 rounded-[3rem] overflow-hidden shadow-[0_80px_250px_rgba(0,0,0,1)] z-[80] origin-top animate-result ring-1 ring-white/10">
                <div className="p-4 flex flex-col">
                  {suggestions.map((suggestion, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSearch(undefined, suggestion)}
                      className="w-full text-left px-12 py-7 text-[16px] text-white/30 hover:text-cyan-300 hover:bg-white/[0.05] rounded-3xl transition-all flex items-center justify-between group"
                    >
                      <div className="flex items-center gap-8">
                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-white/10 group-hover:text-cyan-400 transition-colors"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                        <span className="font-light tracking-tight">{suggestion}</span>
                      </div>
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="opacity-0 group-hover:opacity-100 -translate-x-6 group-hover:translate-x-0 transition-all"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {attachedFile && (
            <div className="mt-8 flex items-center gap-6 px-10 py-4 bg-cyan-500/10 border border-cyan-500/30 rounded-full animate-result shadow-3xl backdrop-blur-3xl ring-1 ring-cyan-500/20">
              <span className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.5em] flex items-center gap-4">
                <div className="w-2.5 h-2.5 rounded-full bg-cyan-400 animate-pulse shadow-[0_0_20px_rgba(34,211,238,1)]" />
                Active Link Node
              </span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 hover:text-white transition-colors p-1">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><path d="M18 6L6 18M6 6l12 12"/></svg>
              </button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-20 w-full flex justify-center gap-24 sm:gap-48 text-[11px] uppercase tracking-[2em] text-white/5 pointer-events-none select-none font-black antialiased opacity-50">
          <span>Global Node Synthesis</span>
          <span>Verified Neural Stream</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
