      id: i,
      left: `${Math.random() * 100}%`,
      top: `${Math.random() * 100}%`,
      size: `${Math.random() * 2 + 1}px`,
      delayVal: Math.random() * 3,
      durationVal: Math.random() * 2 + 1,
    }));
  }, []);

  return (
    <div className="absolute inset-0 pointer-events-none">
      {particles.map((p) => (
        <div
          key={p.id}
          className="absolute bg-cyan-400 rounded-full blur-[1px] shadow-[0_0_10px_rgba(34,211,238,0.8)]"
          style={{
            left: p.left,
            top: p.top,
            width: p.size,
            height: p.size,
            animation: `spark-flicker ${p.durationVal}s infinite ease-in-out ${p.delayVal}s, spark-float ${p.durationVal * 2}s infinite ease-in-out`,
          }}
        />
      ))}
    </div>
  );
};

