const ThinkingIndicator: React.FC<{ status: string }> = ({ status }) => (
  <div className="flex items-center gap-4 px-8 py-5 border-b border-white/[0.04] bg-white/[0.01]">
    <div className="flex gap-2">
      <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce shadow-[0_0_10px_rgba(34,211,238,1)]" />
      <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.1s] shadow-[0_0_10px_rgba(34,211,238,0.7)]" />
      <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.2s] shadow-[0_0_10px_rgba(34,211,238,0.4)]" />
    </div>
    <span className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.5em] animate-pulse">{status}</span>
    <div className="flex-1 h-[1px] bg-gradient-to-r from-cyan-500/10 to-transparent ml-4" />
  </div>
);

const formatLine = (line: string) => {
  return line
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') 
    .replace(/\*\*/g, '') 
    .replace(/`(.*?)`/g, '<code>$1</code>');
};

const FormattedContent: React.FC<{ content: string }> = ({ content }) => {
  const renderTokens = useMemo(() => {
    const lines = content.split('\n');
    const elements: React.ReactNode[] = [];
    let currentCodeBlock: string[] | null = null;

    lines.forEach((line, i) => {
      if (line.trim().startsWith('```')) {
        if (currentCodeBlock) {
          elements.push(
            <pre key={`pre-${i}`} className="animate-result overflow-x-auto my-4 p-4 bg-white/5 rounded-xl border border-white/10" style={{ animationDelay: `${i * 0.05}s` }}><code>{currentCodeBlock.join('\n')}</code></pre>
          );
          currentCodeBlock = null;
        } else {
          currentCodeBlock = [];
        }
        return;
      }

      if (currentCodeBlock) {
        currentCodeBlock.push(line);
        return;
      }

      const style = { animationDelay: `${i * 0.05}s` };

      if (line.startsWith('# ')) {
        elements.push(<h1 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: formatLine(line.replace('# ', '')) }} />);
      } else if (line.startsWith('## ')) {
        elements.push(<h2 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: formatLine(line.replace('## ', '')) }} />);
      } else if (line.startsWith('### ')) {
        elements.push(<h3 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: formatLine(line.replace('### ', '')) }} />);
      } 
      else if (line.trim().startsWith('- ') || line.trim().startsWith('* ')) {
        const text = line.trim().substring(2);
        elements.push(
          <li key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: formatLine(text) }} />
        );
      } 
      else if (line.trim()) {
        elements.push(<p key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: formatLine(line) }} />);
      }
    });

    return elements;
  }, [content]);

  return <div className="md-content">{renderTokens}</div>;
};

type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [status, setStatus] = useState('Thinking...');
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze Payload" }]);
    setIsLoading(true);
    setStatus('Initializing Uplink...');
    setError(null);

    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.generateTopicImage(finalQuery || "Conceptual visualization");
      setStatus('Retrieving Web Context...');
      const stream = geminiService.streamSearch(finalQuery || "Analyze provided search context.", currentFile || undefined);

      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          setStatus('Neural Synthesis...');
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          const finalImage = await imageGenPromise;
          const related = await geminiService.generateRelatedQueries(finalQuery, accumulatedText);
          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              sources: chunk.sources,
              images: finalImage ? [finalImage] : [],
              relatedQueries: related
            };
            return newMsgs;
          });
          setActiveTabs(prev => ({ ...prev, [messages.length + 1]: 'synthesis' }));
          setIsLoading(false);
        }
      }
    } catch (err: any) {
      setError(err.message === 'QUOTA_EXCEEDED' ? "Neural limits reached." : "Uplink connection lost.");
      setMessages(prev => (prev.length > 0 && prev[prev.length-1].role === 'assistant' && !prev[prev.length-1].content) ? prev.slice(0, -1) : prev);
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      setTimeout(() => {
        scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
      }, 100);
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;
  const canSubmit = query.trim().length > 0 || attachedFile !== null;

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden font-sans selection:bg-cyan-500/20">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-4 sm:px-8 ${hasHistory ? 'h-16 border-b border-white/[0.05] bg-black/60 backdrop-blur-xl' : 'h-[35vh] items-end justify-center pb-8'}`}>
        <SparkleTitle hasHistory={hasHistory} isLoading={isLoading} />
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-[920px] mx-auto px-4 sm:px-8 overflow-y-auto pt-24 sm:pt-36 pb-64 transition-all duration-1000 custom-scroll ${hasHistory ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-16">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              {msg.role === 'user' ? (
                <div className="flex items-center gap-6 py-6 px-4">
                  <div className="w-10 h-10 rounded-2xl bg-white/[0.05] border border-white/10 flex items-center justify-center text-[10px] font-black text-white/30 shrink-0 shadow-xl rotate-6">USER</div>
                  <h2 className="text-xl sm:text-3xl font-light text-white/90 tracking-tight leading-snug" dangerouslySetInnerHTML={{ __html: formatLine(msg.content) }} />
                </div>
              ) : (
                <div className="flex flex-col border border-white/[0.08] bg-white/[0.02] backdrop-blur-[40px] rounded-[2.5rem] overflow-hidden shadow-2xl transition-all ring-1 ring-white/5">

                  {idx === messages.length - 1 && isLoading && <ThinkingIndicator status={status} />}

                  <div className="flex flex-wrap items-center px-6 py-4 border-b border-white/[0.03] bg-white/[0.02] gap-4">
                    <div className="flex bg-white/[0.04] p-1 rounded-full gap-1 border border-white/5">
                      {['synthesis', 'media', 'references'].map((tab) => (
                        <button
                          key={tab}
                          onClick={() => setActiveTabs(prev => ({ ...prev, [idx]: tab as ViewMode }))}
                          className={`px-4 sm:px-7 py-2 rounded-full text-[9px] font-bold uppercase tracking-[0.2em] transition-all duration-500 ${
                            (activeTabs[idx] || 'synthesis') === tab 
                            ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/20 shadow-[0_0_20px_rgba(34,211,238,0.1)]' 
                            : 'text-white/20 hover:text-white/60'
                          }`}
                        >
                          {tab === 'references' ? 'Sources' : tab}
                        </button>
                      ))}
                    </div>
                    <div className="flex-1" />
                    <div className="hidden sm:flex items-center gap-3 opacity-20">
                      <div className="w-1 h-1 rounded-full bg-cyan-400" />
                      <div className="text-[8px] font-mono text-cyan-400 uppercase tracking-widest">UPLINK ACTIVE</div>
                    </div>
                  </div>

                  <div className="p-8 sm:p-14 min-h-[300px]">
                    {(activeTabs[idx] || 'synthesis') === 'synthesis' && (
                      <div className="animate-fade-scale text-[15px] sm:text-[17px]">
                        <FormattedContent content={msg.content} />
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'media' && (
                      <div className="animate-fade-scale grid grid-cols-1 gap-10">
                        {msg.images?.map((img, i) => (
                          <div key={i} className="relative rounded-[2rem] overflow-hidden border border-white/5 aspect-video bg-black/80">
                            <img src={img} alt="Synthesis" className="w-full h-full object-cover opacity-90" />
                          </div>
                        )) || <div className="h-48 border border-dashed border-white/5 rounded-[2rem] flex items-center justify-center opacity-20 text-[9px] uppercase tracking-widest">No Visual Data</div>}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'references' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {msg.sources?.map((source, i) => (
                          <a key={i} href={source.uri} target="_blank" rel="noopener noreferrer" className="p-6 rounded-[2rem] border border-white/5 bg-white/[0.02] hover:bg-cyan-500/5 transition-all flex flex-col gap-3">
                            <h4 className="text-[13px] font-bold text-white/80 line-clamp-1">{source.title}</h4>
                            <p className="text-[9px] text-cyan-400/40 font-mono tracking-tighter uppercase truncate">{new URL(source.uri).hostname}</p>
                          </a>
                        )) || <div className="col-span-2 text-center opacity-10 py-12 uppercase tracking-widest text-[10px]">Reference Link Table Empty</div>}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}

          {!isLoading && messages.length > 0 && (
            <div className="animate-result grid grid-cols-1 sm:grid-cols-3 gap-4 pt-10 pb-20">
              {(messages[messages.length-1].relatedQueries || ["Synthesis deep-dive", "Historical context", "Market projections"]).map((text, i) => (
                <button
                  key={i}
                  onClick={() => handleSearch(undefined, text)}
                  className="p-8 rounded-[2rem] border border-white/5 bg-white/[0.01] hover:bg-cyan-500/[0.02] hover:border-cyan-500/30 transition-all text-left group"
                >
                  <div className="w-10 h-10 rounded-full bg-cyan-500/10 flex items-center justify-center text-cyan-400 mb-6 group-hover:scale-110 transition-transform">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 6v12a3 3 0 1 0 3-3H6a3 3 0 1 0 3 3V6a3 3 0 1 0-3 3h12a3 3 0 1 0-3-3z"/></svg>
                  </div>
                  <span className="text-[13px] text-white/30 group-hover:text-white transition-colors">{text}</span>
                </button>
              ))}
            </div>
          )}
        </div>
      </main>

      <div className={`fixed left-0 right-0 px-4 flex flex-col items-center z-[70] transition-all duration-1000 ${hasHistory ? 'bottom-8 sm:bottom-12' : 'top-[50vh] -translate-y-1/2'}`}>
        <div className="w-full max-w-2xl flex flex-col items-center">
          <form onSubmit={handleSearch} className="w-full relative">
            <div className="relative rounded-[2.5rem] bg-white/[0.04] backdrop-blur-[50px] border border-white/10 shadow-2xl transition-all duration-700 focus-within:border-cyan-500/50 focus-within:shadow-[0_0_80px_rgba(34,211,238,0.15)] ring-1 ring-white/5">
              <button type="button" onClick={() => fileInputRef.current?.click()} className={`absolute left-6 top-1/2 -translate-y-1/2 p-3 rounded-2xl ${attachedFile ? 'bg-cyan-500 text-black' : 'text-white/20 hover:text-cyan-400'}`}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l8.57-8.57a4 4 0 1 1 5.66 5.66l-8.59 8.51a2 2 0 0 1-2.83-2.83l8.49-8.48" /></svg>
              </button>
              <input type="file" ref={fileInputRef} className="hidden" onChange={async (e) => {
                const file = e.target.files?.[0];
                if (file) {
                  const reader = new FileReader();
                  reader.onloadend = () => setAttachedFile({ data: (reader.result as string).split(',')[1], mimeType: file.type });
                  reader.readAsDataURL(file);
                }
              }} />
              <input
                type="text" value={query} 
                onChange={(e) => setQuery(e.target.value)}
                placeholder={isListening ? "Listening..." : "Search anything..."}
                className="w-full bg-transparent pl-16 pr-32 sm:pr-40 py-6 text-white placeholder-white/10 focus:outline-none text-lg font-light tracking-tight"
                autoFocus
              />
              <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                <button type="button" onClick={toggleVoiceSearch} className={`p-3 rounded-full ${isListening ? 'bg-red-500/60' : 'text-white/10 hover:text-cyan-400'}`}>
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/></svg>
                </button>
                <button type="submit" disabled={!canSubmit || isLoading} className={`p-4 rounded-full transition-all duration-700 ${canSubmit ? 'bg-cyan-500 text-black' : 'bg-white/5 text-white/10 opacity-30'}`}>
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                </button>
              </div>
            </div>

            {showSuggestions && suggestions.length > 0 && (
              <div ref={suggestionRef} className="absolute bottom-full mb-4 left-6 right-6 bg-black/90 backdrop-blur-[60px] border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl z-[80] animate-result">
                <div className="p-3">
                  {suggestions.map((s, i) => (
                    <button key={i} onClick={() => handleSearch(undefined, s)} className="w-full text-left px-8 py-5 text-[14px] text-white/30 hover:text-cyan-400 hover:bg-white/[0.04] rounded-3xl transition-all font-light">
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {attachedFile && (
            <div className="mt-4 px-6 py-2 bg-cyan-500/10 border border-cyan-500/30 rounded-full animate-result flex items-center gap-3">
              <span className="text-[9px] font-black text-cyan-400 uppercase tracking-widest">Payload Active</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 p-1"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

