                </div>
              )}
            </div>
          ))}

          {!isLoading && messages.length > 0 && (
            <div className="animate-result grid grid-cols-1 sm:grid-cols-3 gap-3 pt-6 pb-20">
              {(messages[messages.length-1].relatedQueries || ["Synthesis deep-dive", "Historical context", "Future models"]).map((text, i) => (
                <button
                  key={i}
                  onClick={() => handleSearch(undefined, text)}
                  className="p-5 sm:p-6 rounded-xl sm:rounded-[2rem] border border-white/5 bg-white/[0.01] hover:bg-cyan-500/[0.03] hover:border-cyan-500/30 transition-all text-left group"
