        </div>
      </main>

      <div className={`fixed left-0 right-0 px-4 flex flex-col items-center z-[70] transition-all duration-1000 ${hasHistory ? 'bottom-6 sm:bottom-10' : 'top-[50vh] -translate-y-1/2'}`}>
        <div className="w-full max-w-2xl flex flex-col items-center relative">
          <form onSubmit={handleSearch} className="w-full relative">
            <div className={`relative rounded-[2rem] sm:rounded-[2.5rem] border border-white/15 shadow-2xl transition-all duration-700 search-glass search-focus-glow ring-1 ring-white/10`}>
              <button type="button" onClick={() => fileInputRef.current?.click()} className={`absolute left-4 sm:left-6 top-1/2 -translate-y-1/2 p-2.5 rounded-xl ${attachedFile ? 'bg-cyan-500 text-black shadow-lg' : 'text-white/25 hover:text-cyan-400'}`}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l8.57-8.57a4 4 0 1 1 5.66 5.66l-8.59 8.51a2 2 0 0 1-2.83-2.83l8.49-8.48" /></svg>
              </button>

              <input type="file" ref={fileInputRef} className="hidden" onChange={async (e) => {
                const file = e.target.files?.[0];
                if (file) {
                  const reader = new FileReader();
                  reader.onloadend = () => setAttachedFile({ data: (reader.result as string).split(',')[1], mimeType: file.type });
                  reader.readAsDataURL(file);
                }
              }} />

              <input
                type="text" value={query} 
                onChange={(e) => setQuery(e.target.value)}
                placeholder={isListening ? "Listening..." : "Request synthesis..."}
                onFocus={() => query.length >= 2 && setShowSuggestions(true)}
                className="w-full bg-transparent pl-14 sm:pl-20 pr-32 sm:pr-40 py-5 sm:py-6 text-white placeholder-white/10 focus:outline-none text-base sm:text-lg font-light tracking-tight"
                autoFocus
              />

              <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-1.5 sm:gap-2">
                <button type="button" onClick={toggleVoiceSearch} className={`p-2.5 sm:p-3 rounded-full transition-colors ${isListening ? 'bg-red-500/60 text-white animate-pulse' : 'text-white/10 hover:text-cyan-400'}`}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/></svg>
                </button>
                <button type="submit" disabled={!canSubmit || isLoading} className={`p-3 sm:p-4 rounded-full transition-all duration-700 ${canSubmit ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/40' : 'bg-white/5 text-white/10 opacity-30'}`}>
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                </button>
              </div>
            </div>

            {/* Suggestions positioning logic: Below on landing, Above on results */}
            {showSuggestions && suggestions.length > 0 && (
              <div 
                ref={suggestionRef} 
                className={`absolute left-4 right-4 bg-black/95 backdrop-blur-[80px] border border-white/15 rounded-[1.8rem] sm:rounded-[2.2rem] overflow-hidden shadow-2xl z-[80] animate-result ${
                  hasHistory ? 'bottom-full mb-4' : 'top-full mt-4'
                }`}
              >
                <div className="p-2 sm:p-3 flex flex-col">
                  {suggestions.map((s, i) => (
                    <button key={i} onClick={() => handleSearch(undefined, s)} className="w-full text-left px-6 py-4 text-[13px] sm:text-[14px] text-white/40 hover:text-cyan-400 hover:bg-white/[0.04] rounded-2xl transition-all font-light">
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {attachedFile && (
            <div className="mt-3 px-5 py-1.5 bg-cyan-500/10 border border-cyan-500/30 rounded-full animate-result flex items-center gap-3">
              <span className="text-[8px] font-black text-cyan-400 uppercase tracking-widest">Payload Active</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 p-0.5 hover:text-white transition-colors"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex flex-col items-center gap-8 animate-result delay-500">
          <div className="flex gap-4 sm:gap-12 opacity-50">
            <button onClick={() => handleSearch(undefined, "Quantum computing breakthroughs")} className="text-[10px] sm:text-[11px] uppercase tracking-[0.4em] text-white/70 hover:text-cyan-400 transition-colors border border-white/15 px-6 py-2.5 rounded-full search-glass">Quantum Computing</button>
            <button onClick={() => handleSearch(undefined, "Next-gen energy technology")} className="text-[10px] sm:text-[11px] uppercase tracking-[0.4em] text-white/70 hover:text-cyan-400 transition-colors border border-white/15 px-6 py-2.5 rounded-full search-glass">Energy Tech</button>
            <button onClick={() => handleSearch(undefined, "AI architecture in 2025")} className="text-[10px] sm:text-[11px] uppercase tracking-[0.4em] text-white/70 hover:text-cyan-400 transition-colors border border-white/15 px-6 py-2.5 rounded-full search-glass">Neural Models</button>
          </div>
          <div className="flex justify-center gap-12 sm:gap-48 text-[11px] uppercase tracking-[2em] text-white/5 pointer-events-none select-none font-black antialiased opacity-50">
            <span>Global Synthesis</span>
            <span>Neural Stream</span>
          </div>
        </div>
      )}
    </div>
  );
};

