import React, { useEffect, useRef } from 'react';

const Background: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let points: Point[] = [];

    class Point {
      x: number;
      y: number;
      baseX: number;
      baseY: number;
      size: number;
      angle: number;

      constructor() {
        this.x = Math.random() * canvas!.width;
        this.y = Math.random() * canvas!.height;
        this.baseX = this.x;
        this.baseY = this.y;
        this.size = Math.random() * 1.5 + 0.5;
        this.angle = Math.random() * Math.PI * 2;
      }

      update(time: number) {
        // Subtle drift in a technology pattern style
        this.x = this.baseX + Math.cos(this.angle + time * 0.001) * 15;
        this.y = this.baseY + Math.sin(this.angle + time * 0.001) * 15;
      }

      draw() {
        if (!ctx) return;
        ctx.fillStyle = `rgba(34, 211, 238, 0.3)`;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      points = [];
      // Fewer points for a cleaner, professional look
      for (let i = 0; i < 30; i++) {
        points.push(new Point());
      }
    };

    const animate = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw technical connecting lines
      ctx.strokeStyle = 'rgba(34, 211, 238, 0.05)';
      ctx.lineWidth = 0.5;

      for (let i = 0; i < points.length; i++) {
        points[i].update(time);
        points[i].draw();

        for (let j = i + 1; j < points.length; j++) {
          const dx = points[i].x - points[j].x;
          const dy = points[i].y - points[j].y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          if (distance < 250) {
            ctx.beginPath();
            ctx.moveTo(points[i].x, points[i].y);
            ctx.lineTo(points[j].x, points[j].y);
            ctx.stroke();
          }
        }
      }

      animationFrameId = requestAnimationFrame(animate);
    };

    init();
    requestAnimationFrame(animate);

    const handleResize = () => {
      init();
    };

    window.addEventListener('resize', handleResize);
    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <div className="fixed inset-0 -z-10 overflow-hidden bg-[#010103]">
      {/* Deep Gradient Void */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_0%,rgba(10,30,50,0.4)_0%,rgba(1,1,3,1)_100%)]" />

      {/* Professional Tech Pattern Overlay */}
      <div className="absolute inset-0 tech-pattern pointer-events-none opacity-40" />

      {/* Atmospheric Micro-Glows */}
      <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-cyan-500/5 blur-[150px] rounded-full animate-pulse" />
      <div className="absolute bottom-[-10%] right-[-5%] w-[30%] h-[30%] bg-blue-500/5 blur-[120px] rounded-full animate-pulse" />

      {/* Structural Tech Elements */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-[0.03]">
         <svg width="100%" height="100%" className="absolute inset-0">
            <defs>
               <pattern id="grid-large" width="100" height="100" patternUnits="userSpaceOnUse">
                  <path d="M 100 0 L 0 0 0 100" fill="none" stroke="white" strokeWidth="0.5"/>
               </pattern>
            </defs>
            <rect width="100%" height="100%" fill="url(#grid-large)" />
         </svg>
      </div>

      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full opacity-30 mix-blend-screen" />
    </div>
  );
};

