      id: i,
      left: `${Math.random() * 100}%`,
      top: `${Math.random() * 100}%`,
      size: `${Math.random() * 2 + 1.2}px`,
      delayVal: Math.random() * 2,
      durationVal: Math.random() * 2.5 + 1.5,
