  }, []);

  return (
    <div className="absolute inset-0 pointer-events-none">
      {particles.map((p) => (
        <div
          key={p.id}
          className="absolute bg-cyan-400 rounded-full blur-[1px] shadow-[0_0_12px_rgba(34,211,238,0.8)]"
