import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { SearchResult } from "../types";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  private ai: GoogleGenAI;
  private langSearchKey = "sk-ed72ffcf8ca147c9a929ed588c93a82e";
  private langSearchUrl = "https://api.langsearch.com/v1/web-search";

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Strictly uses LangSearch API for retrieval.
   * Does not rely on Gemini's built-in tools for search.
   */
  private async fetchLangSearch(query: string) {
    try {
      const response = await fetch(this.langSearchUrl, {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${this.langSearchKey}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          query: query,
          freshness: "noLimit",
          summary: true,
          count: 12 // Increased context window
        })
      });

      const json = await response.json();

      if (json.code === 200 && json.data?.webPages?.value) {
        return json.data.webPages.value;
      }
      return [];
    } catch (error) {
      console.error("[Spark Node] Retrieval Interruption:", error);
      return [];
    }
  }

  private async withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 1000): Promise<T> {
    try {
      return await fn();
    } catch (error: any) {
      const errorStr = JSON.stringify(error).toUpperCase();
      const isQuotaError = 
        errorStr.includes('429') || 
        errorStr.includes('RESOURCE_EXHAUSTED') || 
        errorStr.includes('QUOTA') ||
        errorStr.includes('RATE_LIMIT');

      if (isQuotaError && retries > 0) {
        await sleep(delay);
        return this.withRetry(fn, retries - 1, delay * 2);
      }
      if (isQuotaError) throw new Error('QUOTA_EXCEEDED');
      throw error;
    }
  }

  /**
   * Synthesis Phase: Gemini transforms LangSearch context into structured insights.
   */
  private async synthesize(query: string, context: string, file?: AttachedFile, isStream = false) {
    const prompt = `
      User Intent: "${query}"

      Data Context (Retrieved via LangSearch):
      ${context}

      Synthesis Parameters:
      1. Provide a definitive, expert analysis based SOLELY on the provided context.
      2. If multiple viewpoints exist in the context, synthesize them into a coherent insight.
      3. Format output with strict Markdown: Use ## for sections, bold for key terms, and triple backticks (\` \` \`) for technical definitions or code snippets.
      4. Use professional, concise language. 
      5. Do not include introductory phrases like "Based on the search results...". Dive straight into the synthesis.
    `;

    const parts: any[] = [{ text: prompt }];
    if (file) {
      parts.push({ inlineData: { data: file.data, mimeType: file.mimeType } });
    }

    // Faster model priority for near-instant results
    const models = ["gemini-3-flash-preview", "gemini-3-pro-preview", "gemini-flash-lite-latest"];

    for (const modelName of models) {
      try {
        if (isStream) {
          return await this.ai.models.generateContentStream({
            model: modelName,
            contents: { parts },
            config: { temperature: 0.1 } // High precision synthesis
          });
        } else {
          const response = await this.ai.models.generateContent({
            model: modelName,
            contents: { parts },
            config: { temperature: 0.1 }
          });
          return response;
        }
      } catch (err: any) {
        const errStr = JSON.stringify(err).toUpperCase();
        if (errStr.includes('429') || errStr.includes('QUOTA') || errStr.includes('RESOURCE_EXHAUSTED')) {
          continue; 
        }
        throw err;
      }
    }
    throw new Error('QUOTA_EXCEEDED');
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      return await this.withRetry(async () => {
        const response = await this.ai.models.generateContent({
          model: "gemini-flash-lite-latest",
          contents: `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        });
        return JSON.parse(response.text || "[]");
      }, 0);
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      return await this.withRetry(async () => {
        const response = await this.ai.models.generateContent({
          model: "gemini-flash-lite-latest",
          contents: `Based on this synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up inquiries for "${query}". JSON array only.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        });
        return JSON.parse(response.text || "[]");
      }, 0);
    } catch { return []; }
  }

  async generateTopicImage(query: string): Promise<string | undefined> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `A formal, sophisticated conceptual visual for: "${query}". Minimalist tech aesthetic, deep blacks, cyan neon accents, ultra-high definition.` }],
        },
        config: { imageConfig: { aspectRatio: "16:9" } },
      });
      const part = response.candidates[0].content.parts.find(p => p.inlineData);
      return part ? `data:image/png;base64,${part.inlineData.data}` : undefined;
    } catch { return undefined; }
  }

  async performSearch(query: string): Promise<SearchResult> {
    const webPages = await this.fetchLangSearch(query);
    const context = webPages.map((p: any) => `Source: ${p.name}\nSnippet: ${p.summary || p.snippet}`).join("\n\n");

    const response = await this.synthesize(query, context) as GenerateContentResponse;

    return {
      text: response.text || "Synthesis engine timed out.",
      sources: webPages.map((p: any) => ({ title: p.name, uri: p.url }))
    };
  }

  async *streamSearch(query: string, file?: AttachedFile) {
    const webPages = await this.fetchLangSearch(query);
    const context = webPages.map((p: any) => `Source: ${p.name}\nContext: ${p.summary || p.snippet}`).join("\n\n");
    const sources = webPages.map((p: any) => ({ title: p.name, uri: p.url }));

    try {
      const stream = await this.synthesize(query, context, file, true) as AsyncIterable<GenerateContentResponse>;

      for await (const chunk of stream) {
        yield { text: chunk.text || "", done: false, sources: [] };
      }

      yield { text: "", done: true, sources };
    } catch (error: any) {
      if (error.message === 'QUOTA_EXCEEDED') throw error;
      throw new Error('Neural Synthesis Error');
    }
  }
}

