import React, { useEffect, useRef } from 'react';

const Background: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let points: Point[] = [];

    class Point {
      x: number;
      y: number;
      baseX: number;
      baseY: number;
      size: number;
      angle: number;
      speed: number;

      constructor() {
        this.x = Math.random() * canvas!.width;
        this.y = Math.random() * canvas!.height;
        this.baseX = this.x;
        this.baseY = this.y;
        this.size = Math.random() * 1.8 + 0.6;
        this.angle = Math.random() * Math.PI * 2;
        this.speed = Math.random() * 0.0008 + 0.0003;
      }

      update(time: number) {
        // Sophisticated orbital drift
        this.x = this.baseX + Math.cos(this.angle + time * this.speed) * 25;
        this.y = this.baseY + Math.sin(this.angle + time * this.speed) * 25;
      }

      draw() {
        if (!ctx) return;
        const opacity = 0.2 + Math.sin(Date.now() * 0.001 + this.angle) * 0.1;
        ctx.fillStyle = `rgba(34, 211, 238, ${opacity})`;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();

        // Add a core glow for some points
        if (this.size > 1.8) {
          ctx.shadowBlur = 10;
          ctx.shadowColor = 'rgba(34, 211, 238, 0.5)';
          ctx.fill();
          ctx.shadowBlur = 0;
        }
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      points = [];
      // Clean, professional node count
      for (let i = 0; i < 35; i++) {
        points.push(new Point());
      }
    };

    const animate = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Technical structural connections
      ctx.strokeStyle = 'rgba(34, 211, 238, 0.06)';
      ctx.lineWidth = 0.6;

      for (let i = 0; i < points.length; i++) {
        points[i].update(time);
        points[i].draw();

        for (let j = i + 1; j < points.length; j++) {
          const dx = points[i].x - points[j].x;
          const dy = points[i].y - points[j].y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          if (distance < 300) {
            // Gradient connection line
            const grad = ctx.createLinearGradient(points[i].x, points[i].y, points[j].x, points[j].y);
            const lineOpacity = (1 - distance / 300) * 0.12;
            grad.addColorStop(0, `rgba(34, 211, 238, ${lineOpacity})`);
            grad.addColorStop(1, `rgba(34, 211, 238, ${lineOpacity * 0.2})`);

            ctx.strokeStyle = grad;
            ctx.beginPath();
            ctx.moveTo(points[i].x, points[i].y);
            ctx.lineTo(points[j].x, points[j].y);
            ctx.stroke();
          }
        }
      }

      animationFrameId = requestAnimationFrame(animate);
    };

    init();
    requestAnimationFrame(animate);

    const handleResize = () => {
      init();
    };

    window.addEventListener('resize', handleResize);
    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <div className="fixed inset-0 -z-10 overflow-hidden bg-[#010103]">
      {/* Prime Deep Gradient */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_0%,rgba(8,24,40,0.45)_0%,rgba(1,1,3,1)_85%)]" />

      {/* Layered Technical Patterns */}
      <div className="absolute inset-0 tech-pattern pointer-events-none" />
      <div className="absolute inset-0 tech-grid-secondary pointer-events-none opacity-20" />

      {/* Atmospheric Focus Regions */}
      <div className="absolute top-[-15%] left-[-10%] w-[50%] h-[50%] bg-cyan-500/[0.03] blur-[180px] rounded-full animate-pulse" />
      <div className="absolute bottom-[-10%] right-[-5%] w-[35%] h-[35%] bg-blue-500/[0.04] blur-[140px] rounded-full animate-pulse" />

      {/* Structural Framing Grid */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-[0.02]">
         <svg width="100%" height="100%" className="absolute inset-0">
            <defs>
               <pattern id="grid-large-classic" width="120" height="120" patternUnits="userSpaceOnUse">
                  <path d="M 120 0 L 0 0 0 120" fill="none" stroke="white" strokeWidth="0.8"/>
               </pattern>
            </defs>
            <rect width="100%" height="100%" fill="url(#grid-large-classic)" />
         </svg>
      </div>

      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full opacity-40 mix-blend-screen" />
    </div>
  );
};

