            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex flex-col items-center gap-10 animate-result delay-500">
          <div className="flex flex-wrap justify-center gap-5 sm:gap-14 px-4">
            <button onClick={() => handleSearch(undefined, "Quantum computing breakthroughs")} className="text-[10px] sm:text-[12px] uppercase tracking-[0.4em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-8 py-3 rounded-full search-glass font-bold">Quantum computing</button>
            <button onClick={() => handleSearch(undefined, "Next-gen solar technology")} className="text-[10px] sm:text-[12px] uppercase tracking-[0.4em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-8 py-3 rounded-full search-glass font-bold">Energy Tech</button>
            <button onClick={() => handleSearch(undefined, "AI architecture in 2025")} className="text-[10px] sm:text-[12px] uppercase tracking-[0.4em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-8 py-3 rounded-full search-glass font-bold">Neural Models</button>
          </div>
          <div className="flex justify-center gap-12 sm:gap-64 text-[12px] uppercase tracking-[2.5em] text-white/5 pointer-events-none select-none font-black antialiased opacity-40">
            <span>Synthesis engine</span>
            <span>Neural stream</span>
          </div>
        </div>
      )}
    </div>
  );
};

