                <button type="button" onClick={toggleVoiceSearch} className={`p-4 rounded-full transition-colors ${isListening ? 'bg-red-500/60 text-white animate-pulse shadow-[0_0_20px_rgba(239,68,68,0.5)]' : 'text-white/15 hover:text-cyan-400'}`}>
