                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                </button>
              </div>
            </div>

            {showSuggestions && suggestions.length > 0 && (
              <div 
                ref={suggestionRef} 
                className={`absolute left-4 right-4 bg-black/98 backdrop-blur-[140px] border border-white/15 rounded-[2.5rem] sm:rounded-[3rem] overflow-hidden shadow-2xl z-[80] animate-result ${
                  hasHistory ? 'bottom-full mb-8' : 'top-full mt-8'
                }`}
              >
                <div className="p-4 flex flex-col gap-1.5">
                  {suggestions.map((s, i) => (
                    <button key={i} onClick={() => handleSearch(undefined, s)} className="w-full text-left px-10 py-6 text-[15px] sm:text-[17px] text-white/40 hover:text-cyan-400 hover:bg-white/[0.06] rounded-[2rem] transition-all font-light tracking-wide">
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {attachedFile && (
            <div className="mt-5 px-8 py-2.5 bg-cyan-500/10 border border-cyan-500/40 rounded-full animate-result flex items-center gap-5 shadow-xl">
              <span className="text-[11px] font-black text-cyan-400 uppercase tracking-[0.4em]">Payload Linked</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 p-1 hover:text-white transition-colors hover:scale-110"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex flex-col items-center gap-12 animate-result delay-500">
          <div className="flex flex-wrap justify-center gap-6 sm:gap-16 px-6">
            <button onClick={() => handleSearch(undefined, "Quantum computing breakthroughs")} className="text-[11px] sm:text-[13px] uppercase tracking-[0.45em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-10 py-3.5 rounded-full search-glass font-bold shadow-md">Quantum computing</button>
            <button onClick={() => handleSearch(undefined, "Next-gen solar technology")} className="text-[11px] sm:text-[13px] uppercase tracking-[0.45em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-10 py-3.5 rounded-full search-glass font-bold shadow-md">Energy Tech</button>
            <button onClick={() => handleSearch(undefined, "AI architecture in 2025")} className="text-[11px] sm:text-[13px] uppercase tracking-[0.45em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-10 py-3.5 rounded-full search-glass font-bold shadow-md">Neural Models</button>
          </div>
          <div className="flex justify-center gap-14 sm:gap-72 text-[13px] uppercase tracking-[2.8em] text-white/5 pointer-events-none select-none font-black antialiased opacity-40">
            <span>Synthesis engine</span>
            <span>Neural stream</span>
          </div>
        </div>
      )}
    </div>
  );
};

