const FormattedContent: React.FC<{ content: string }> = ({ content }) => {
  const parseMarkdown = useCallback((text: string) => {
    return text
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') 
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/`(.*?)`/g, '<code class="md-inline-code">$1</code>');
  }, []);

  const renderLines = useMemo(() => {
    const lines = content.split('\n');
    const elements: React.ReactNode[] = [];
    let currentCodeBlock: string[] | null = null;

    lines.forEach((line, i) => {
      const trimmedLine = line.trim();

      if (trimmedLine.startsWith('```')) {
        if (currentCodeBlock) {
          elements.push(
            <pre key={`code-${i}`} className="md-code-block animate-result">
              <code>{currentCodeBlock.join('\n')}</code>
            </pre>
          );
          currentCodeBlock = null;
        } else {
          currentCodeBlock = [];
        }
        return;
      }

      if (currentCodeBlock !== null) {
        currentCodeBlock.push(line);
        return;
      }

      const style = { animationDelay: `${Math.min(i * 0.045, 1.4)}s` };

      if (trimmedLine.startsWith('# ')) {
        elements.push(<h1 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(trimmedLine.replace('# ', '')) }} />);
      } else if (trimmedLine.startsWith('## ')) {
        elements.push(<h2 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(trimmedLine.replace('## ', '')) }} />);
      } else if (trimmedLine.startsWith('### ')) {
        elements.push(<h3 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(trimmedLine.replace('### ', '')) }} />);
      } 
      else if (trimmedLine.match(/^[-*]\s/)) {
        const text = trimmedLine.replace(/^[-*]\s/, '');
        elements.push(
          <li key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(text) }} />
        );
      } 
      else if (trimmedLine) {
        elements.push(<p key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(line) }} />);
      }
    });

    return elements;
  }, [content, parseMarkdown]);

  return <div className="md-content">{renderLines}</div>;
};

type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze Payload" }]);
    setIsLoading(true);
    setError(null);

    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.generateTopicImage(finalQuery || "Conceptual visualization");
      const stream = geminiService.streamSearch(finalQuery || "Analyze provided search context.", currentFile || undefined);

      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          const [finalImage, related] = await Promise.all([
            imageGenPromise,
            geminiService.generateRelatedQueries(finalQuery, accumulatedText)
          ]);

          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              sources: chunk.sources,
              images: finalImage ? [finalImage] : [],
              relatedQueries: related
            };
            return newMsgs;
          });
          setActiveTabs(prev => ({ ...prev, [messages.length + 1]: 'synthesis' }));
          setIsLoading(false);
        }
      }
    } catch (err: any) {
      setError(err.message === 'QUOTA_EXCEEDED' ? "Quota limits reached." : "Neural link dropped.");
      setMessages(prev => (prev.length > 0 && prev[prev.length-1].role === 'assistant' && !prev[prev.length-1].content) ? prev.slice(0, -1) : prev);
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;
  const canSubmit = query.trim().length > 0 || attachedFile !== null;

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden font-sans selection:bg-cyan-500/20">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-4 sm:px-8 ${
        hasHistory ? 'h-16 header-glass' : 'h-[32vh] sm:h-[38vh] items-end justify-center pb-8'
      } ${isLoading ? 'header-loading-glow' : ''}`}>
        <SparkleTitle hasHistory={hasHistory} isLoading={isLoading} />
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-[1000px] mx-auto px-4 sm:px-12 overflow-y-auto pt-24 sm:pt-40 pb-48 transition-all duration-1000 custom-scroll ${hasHistory ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-16 sm:gap-28">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              {msg.role === 'user' ? (
                <div className="flex flex-col gap-1 py-10 px-4">
                   <div className="flex items-center gap-6 sm:gap-8">
                    <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-2xl bg-white/[0.06] border border-white/10 flex items-center justify-center text-[11px] font-black text-white/50 shrink-0 shadow-xl rotate-3 uppercase tracking-tighter">Node</div>
                    <h2 className="text-2xl sm:text-4xl md:text-5xl font-light text-white/95 tracking-tight leading-snug">{msg.content}</h2>
                  </div>
                  {idx === messages.length - 1 && isLoading && !messages.find((m, i) => i > idx) && (
                    <div className="pl-16 sm:pl-20">
                      <ThinkingIndicator />
                    </div>
                  )}
                </div>
              ) : (
                <div className="flex flex-col border border-white/[0.1] bg-white/[0.02] backdrop-blur-[70px] rounded-[3rem] sm:rounded-[3.8rem] overflow-hidden shadow-2xl transition-all ring-1 ring-white/5">
                  <div className="flex flex-wrap items-center px-6 sm:px-10 py-5 border-b border-white/[0.04] bg-white/[0.03] gap-2">
                    <div className="flex bg-white/[0.06] p-2 rounded-full gap-1.5 border border-white/5">
                      {['synthesis', 'media', 'references'].map((tab) => (
                        <button
                          key={tab}
                          onClick={() => setActiveTabs(prev => ({ ...prev, [idx]: tab as ViewMode }))}
                          className={`px-5 sm:px-10 py-2.5 rounded-full text-[10px] sm:text-[12px] font-bold uppercase tracking-[0.3em] transition-all duration-300 ${
                            (activeTabs[idx] || 'synthesis') === tab 
                            ? 'bg-cyan-500/30 text-cyan-400 border border-cyan-500/25 shadow-[0_0_30px_rgba(34,211,238,0.2)]' 
                            : 'text-white/35 hover:text-white/75'
                          }`}
                        >
                          {tab === 'references' ? 'Sources' : tab}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="p-10 sm:p-20 min-h-[300px]">
                    {(activeTabs[idx] || 'synthesis') === 'synthesis' && (
                      <div className="animate-fade-scale">
                        <FormattedContent content={msg.content} />
                        {idx === messages.length - 1 && isLoading && msg.content && (
                          <div className="flex items-center gap-5 mt-12 opacity-50">
                             <div className="thinking-spark-container scale-75">
                               <div className="thinking-spark-ring"></div>
                               <div className="thinking-spark-core"></div>
                             </div>
                             <span className="text-[11px] font-bold uppercase tracking-[0.45em] text-cyan-400/80">Streaming Neural Feedback...</span>
                          </div>
                        )}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'media' && (
                      <div className="animate-fade-scale grid grid-cols-1 gap-12">
                        {msg.images?.map((img, i) => (
                          <div key={i} className="relative rounded-[2rem] sm:rounded-[3rem] overflow-hidden border border-white/10 aspect-video bg-black/95 shadow-2xl">
                            <img src={img} alt="Synthesis" className="w-full h-full object-cover opacity-95 hover:scale-105 transition-transform duration-1000" />
                          </div>
                        )) || <div className="h-56 border border-dashed border-white/15 rounded-3xl flex items-center justify-center opacity-30 text-[11px] uppercase tracking-[0.6em] font-black">Visual stream offline</div>}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'references' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-8">
                        {msg.sources?.map((source, i) => (
                          <a key={i} href={source.uri} target="_blank" rel="noopener noreferrer" className="p-8 sm:p-12 rounded-[2.5rem] sm:rounded-[3.5rem] border border-white/12 bg-white/[0.04] hover:bg-cyan-500/12 hover:border-cyan-500/50 transition-all flex flex-col gap-5 group">
                            <h4 className="text-[16px] sm:text-[19px] font-bold text-white/95 group-hover:text-cyan-400 transition-colors line-clamp-1 leading-tight">{source.title}</h4>
                            <p className="text-[11px] text-cyan-400/60 font-mono tracking-tighter uppercase truncate">{new URL(source.uri).hostname}</p>
                          </a>
                        )) || <div className="col-span-2 text-center opacity-25 py-24 uppercase tracking-[0.7em] text-[12px] font-black">Context references cleared</div>}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}

          {!isLoading && messages.length > 0 && (
            <div className="animate-result grid grid-cols-1 sm:grid-cols-3 gap-6 pt-12 pb-44">
              {(messages[messages.length-1].relatedQueries || ["Quantum leap analysis", "Neural infrastructure", "Future of Synthesis"]).map((text, i) => (
                <button
                  key={i}
                  onClick={() => handleSearch(undefined, text)}
                  className="p-10 sm:p-12 rounded-[2.5rem] sm:rounded-[4rem] border border-white/12 bg-white/[0.03] hover:bg-cyan-500/[0.08] hover:border-cyan-500/50 transition-all text-left group shadow-2xl"
                >
                  <div className="w-12 h-12 rounded-full bg-cyan-500/15 flex items-center justify-center text-cyan-400 mb-8 group-hover:scale-115 group-hover:bg-cyan-500/25 transition-all">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 6v12a3 3 0 1 0 3-3H6a3 3 0 1 0 3 3V6a3 3 0 1 0-3 3h12a3 3 0 1 0-3-3z"/></svg>
                  </div>
                  <span className="text-[14px] sm:text-[16px] text-white/45 group-hover:text-white transition-colors line-clamp-2 leading-relaxed font-semibold">{text}</span>
                </button>
              ))}
            </div>
          )}
