          </form>

          {attachedFile && (
            <div className="mt-6 px-10 py-3 bg-cyan-500/15 border border-cyan-500/45 rounded-full animate-result flex items-center gap-6 shadow-2xl">
              <span className="text-[12px] font-black text-cyan-400 uppercase tracking-[0.5em]">Payload Linked</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 p-1.5 hover:text-white transition-colors hover:scale-125"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex flex-col items-center gap-14 animate-result delay-500">
          <div className="flex flex-wrap justify-center gap-8 sm:gap-20 px-8">
            <button onClick={() => handleSearch(undefined, "Quantum computing breakthroughs")} className="text-[12px] sm:text-[14px] uppercase tracking-[0.5em] text-white/65 hover:text-cyan-400 transition-all border border-white/12 px-12 py-4 rounded-full search-glass font-bold shadow-xl">Quantum computing</button>
            <button onClick={() => handleSearch(undefined, "Next-gen solar technology")} className="text-[12px] sm:text-[14px] uppercase tracking-[0.5em] text-white/65 hover:text-cyan-400 transition-all border border-white/12 px-12 py-4 rounded-full search-glass font-bold shadow-xl">Energy Tech</button>
            <button onClick={() => handleSearch(undefined, "AI architecture in 2025")} className="text-[12px] sm:text-[14px] uppercase tracking-[0.5em] text-white/65 hover:text-cyan-400 transition-all border border-white/12 px-12 py-4 rounded-full search-glass font-bold shadow-xl">Neural Models</button>
          </div>
          <div className="flex justify-center gap-16 sm:gap-80 text-[14px] uppercase tracking-[3.2em] text-white/5 pointer-events-none select-none font-black antialiased opacity-40">
            <span>Synthesis engine</span>
            <span>Neural stream</span>
