            <div className={`flex items-center gap-0 relative rounded-[3rem] sm:rounded-[4rem] transition-all duration-700 search-glass search-focus-glow ring-1 ring-white/20 ${isLoading ? 'border-cyan-500/80 shadow-[0_0_100px_rgba(34,211,238,0.4)]' : ''}`}>

