                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {attachedFile && (
            <div className="mt-8 px-12 py-4 bg-cyan-500/20 border border-cyan-500/50 rounded-full animate-result flex items-center gap-7 shadow-2xl">
              <span className="text-[13px] font-black text-cyan-400 uppercase tracking-[0.6em]">Payload Linked</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 p-2 hover:text-white transition-colors hover:scale-130"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
