        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex flex-col items-center gap-16 animate-result delay-500">
          <div className="flex flex-wrap justify-center gap-10 sm:gap-24 px-10">
            <button onClick={() => handleSearch(undefined, "Quantum computing breakthroughs")} className="text-[13px] sm:text-[15px] uppercase tracking-[0.55em] text-white/70 hover:text-cyan-400 transition-all border border-white/15 px-14 py-5 rounded-full search-glass font-bold shadow-2xl">Quantum computing</button>
            <button onClick={() => handleSearch(undefined, "Next-gen solar technology")} className="text-[13px] sm:text-[15px] uppercase tracking-[0.55em] text-white/70 hover:text-cyan-400 transition-all border border-white/15 px-14 py-5 rounded-full search-glass font-bold shadow-2xl">Energy Tech</button>
            <button onClick={() => handleSearch(undefined, "AI architecture in 2025")} className="text-[13px] sm:text-[15px] uppercase tracking-[0.55em] text-white/70 hover:text-cyan-400 transition-all border border-white/15 px-14 py-5 rounded-full search-glass font-bold shadow-2xl">Neural Models</button>
          </div>
          <div className="flex justify-center gap-20 sm:gap-96 text-[16px] uppercase tracking-[3.5em] text-white/5 pointer-events-none select-none font-black antialiased opacity-40">
            <span>Synthesis engine</span>
            <span>Neural stream</span>
