                className={`absolute left-4 right-4 bg-black/98 backdrop-blur-[120px] border border-white/15 rounded-[2.2rem] sm:rounded-[2.8rem] overflow-hidden shadow-2xl z-[80] animate-result ${
                  hasHistory ? 'bottom-full mb-6' : 'top-full mt-6'
