                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>

          {attachedFile && (
            <div className="mt-4 px-6 py-2 bg-cyan-500/10 border border-cyan-500/40 rounded-full animate-result flex items-center gap-4 shadow-xl">
              <span className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.4em]">Payload Linked</span>
              <button onClick={() => setAttachedFile(null)} className="text-cyan-400 p-1 hover:text-white transition-colors hover:scale-110"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12"/></svg></button>
            </div>
          )}
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-12 w-full flex flex-col items-center gap-10 animate-result delay-500">
          <div className="flex flex-wrap justify-center gap-5 sm:gap-14 px-6">
            <button onClick={() => handleSearch(undefined, "Quantum computing breakthroughs")} className="text-[11px] sm:text-[12px] uppercase tracking-[0.4em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-8 py-3 rounded-full search-glass font-bold shadow-md">Quantum computing</button>
            <button onClick={() => handleSearch(undefined, "Next-gen solar technology")} className="text-[11px] sm:text-[12px] uppercase tracking-[0.4em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-8 py-3 rounded-full search-glass font-bold shadow-md">Energy Tech</button>
            <button onClick={() => handleSearch(undefined, "AI architecture in 2025")} className="text-[11px] sm:text-[12px] uppercase tracking-[0.4em] text-white/60 hover:text-cyan-400 transition-all border border-white/10 px-8 py-3 rounded-full search-glass font-bold shadow-md">Neural Models</button>
          </div>
          <div className="flex justify-center gap-12 sm:gap-64 text-[12px] uppercase tracking-[2.5em] text-white/5 pointer-events-none select-none font-black antialiased opacity-40">
            <span>Synthesis engine</span>
            <span>Neural stream</span>
          </div>
        </div>
      )}
    </div>
  );
};

