        </div>
      </main>

      <div className={`fixed left-0 right-0 px-4 flex flex-col items-center z-[70] transition-all duration-1000 ${hasHistory ? 'bottom-6 sm:bottom-10' : 'top-[50vh] -translate-y-1/2'}`}>
