export default App;

import { GoogleGenAI, Type } from "@google/genai";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  private async withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 1000): Promise<T> {
    try {
      return await fn();
    } catch (error: any) {
      const errorStr = JSON.stringify(error).toUpperCase();
      const isQuotaError = 
        errorStr.includes('429') || 
        errorStr.includes('RESOURCE_EXHAUSTED') || 
        errorStr.includes('QUOTA') ||
        errorStr.includes('RATE_LIMIT');

      if (isQuotaError && retries > 0) {
        await sleep(delay);
        return this.withRetry(fn, retries - 1, delay * 2);
      }
      throw error;
    }
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on this synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up inquiries for "${query}". JSON array only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateTopicImage(query: string): Promise<string | undefined> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `A formal, sophisticated conceptual visual for: "${query}". Minimalist tech aesthetic, deep blacks, cyan neon accents, ultra-high definition.` }],
        },
        config: { imageConfig: { aspectRatio: "16:9" } },
      });
      const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
      return part ? `data:image/png;base64,${part.inlineData.data}` : undefined;
    } catch { return undefined; }
  }

  async *streamSearch(query: string, file?: AttachedFile) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: query }];
    if (file) {
      parts.push({ inlineData: { data: file.data, mimeType: file.mimeType } });
    }

    try {
      // Use gemini-3-flash-preview for optimized real-time data fetching via search grounding
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: { parts },
        config: {
          tools: [{ googleSearch: {} }],
          temperature: 0.2,
        },
      });

      let finalSources: Array<{ title: string; uri: string }> = [];

      for await (const chunk of result) {
        const text = chunk.text || "";

        const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
        const chunks = groundingMetadata?.groundingChunks;

        if (chunks) {
          chunks.forEach(c => {
            if (c.web && c.web.uri) {
              if (!finalSources.find(s => s.uri === c.web!.uri)) {
                finalSources.push({ title: c.web.title || "Source", uri: c.web.uri });
              }
            }
          });
        }

        yield { text, done: false, sources: [] };
      }

      yield { text: "", done: true, sources: finalSources };
    } catch (error: any) {
      console.error("Neural stream error:", error);
      const errStr = JSON.stringify(error).toUpperCase();
      if (errStr.includes('QUOTA') || errStr.includes('429')) throw new Error('QUOTA_EXCEEDED');
      throw new Error('Neural Synthesis Error');
    }
  }
}

