const FormattedContent: React.FC<{ content: string }> = ({ content }) => {
  const parseMarkdown = useCallback((text: string) => {
    return text
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') 
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/`(.*?)`/g, '<code class="md-inline-code">$1</code>');
  }, []);

  const renderLines = useMemo(() => {
    const lines = content.split('\n');
    const elements: React.ReactNode[] = [];
    let currentCodeBlock: string[] | null = null;

    lines.forEach((line, i) => {
      const trimmedLine = line.trim();

      if (trimmedLine.startsWith('```')) {
        if (currentCodeBlock) {
          elements.push(
            <pre key={`code-${i}`} className="md-code-block animate-result">
              <code>{currentCodeBlock.join('\n')}</code>
            </pre>
          );
          currentCodeBlock = null;
        } else {
          currentCodeBlock = [];
        }
        return;
      }

      if (currentCodeBlock !== null) {
        currentCodeBlock.push(line);
        return;
      }

      const style = { animationDelay: `${Math.min(i * 0.03, 1.0)}s` };

      if (trimmedLine.startsWith('# ')) {
        elements.push(<h1 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(trimmedLine.replace('# ', '')) }} />);
      } else if (trimmedLine.startsWith('## ')) {
        elements.push(<h2 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(trimmedLine.replace('## ', '')) }} />);
      } else if (trimmedLine.startsWith('### ')) {
        elements.push(<h3 key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(trimmedLine.replace('### ', '')) }} />);
      } 
      else if (trimmedLine.match(/^[-*]\s/)) {
        const text = trimmedLine.replace(/^[-*]\s/, '');
        elements.push(
          <li key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(text) }} />
        );
      } 
      else if (trimmedLine) {
        elements.push(<p key={i} className="animate-result" style={style} dangerouslySetInnerHTML={{ __html: parseMarkdown(line) }} />);
      }
    });

    return elements;
  }, [content, parseMarkdown]);

  return <div className="md-content">{renderLines}</div>;
};

type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isEnhanced, setIsEnhanced] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze Payload" }]);
    setIsLoading(true);
    setIsEnhanced(false);
    setError(null);

    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.generateTopicImage(finalQuery || "Conceptual visualization");
      const stream = geminiService.streamSearch(finalQuery || "Analyze provided search context.", currentFile || undefined);

      let assistantMsgAdded = false;
      let accumulatedText = '';

      for await (const chunk of stream) {
        if (chunk.isEnhanced) setIsEnhanced(true);

        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { role: 'assistant', content: accumulatedText }]);
            assistantMsgAdded = true;
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { ...newMsgs[newMsgs.length - 1], content: accumulatedText };
              return newMsgs;
            });
          }
        } else {
          const [finalImage, related] = await Promise.all([
            imageGenPromise,
            geminiService.generateRelatedQueries(finalQuery, accumulatedText)
          ]);

          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              sources: chunk.sources,
              images: finalImage ? [finalImage] : [],
              relatedQueries: related
            };
            return newMsgs;
          });
          setActiveTabs(prev => ({ ...prev, [messages.length + 1]: 'synthesis' }));
          setIsLoading(false);
        }
      }
    } catch (err: any) {
      setError("Neural link unstable. Refresh recommended.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;
  const canSubmit = query.trim().length > 0 || attachedFile !== null;

  const ghostText = useMemo(() => {
    if (!query || suggestions.length === 0) return '';
    const firstMatch = suggestions[0];
    if (firstMatch.toLowerCase().startsWith(query.toLowerCase())) {
      return firstMatch.slice(query.length);
    }
    return '';
  }, [query, suggestions]);

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden font-sans selection:bg-cyan-500/20">
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-6 sm:px-16 ${
        hasHistory ? 'h-20 header-glass' : 'h-[32vh] sm:h-[38vh] items-end justify-center pb-8'
      } ${isLoading ? 'header-loading-glow' : ''}`}>
        <SparkleTitle hasHistory={hasHistory} isLoading={isLoading} />
        {isEnhanced && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 px-4 py-1 rounded-full bg-pink-500/10 border border-pink-500/30 text-[9px] font-black text-pink-400 uppercase tracking-[0.4em] animate-pulse">
            Enhanced Path Active
          </div>
        )}
        {hasHistory && <div className="header-accent-line" />}
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-[920px] mx-auto px-4 sm:px-12 overflow-y-auto pt-28 sm:pt-36 pb-64 transition-all duration-1000 custom-scroll ${hasHistory ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-12 sm:gap-18">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              {msg.role === 'user' ? (
                <div className="flex flex-col gap-1 py-8 px-4">
                   <div className="flex items-center gap-5 sm:gap-7">
                    <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-xl bg-white/[0.05] border border-white/10 flex items-center justify-center text-[10px] font-black text-white/40 shrink-0 shadow-lg rotate-2 uppercase tracking-tighter">Node</div>
                    <h2 className="text-xl sm:text-2xl md:text-3xl font-light text-white/95 tracking-tight leading-snug">{msg.content}</h2>
                  </div>
