const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  // IMPLEMENTATION: Langsearch API Key defined as a private constant
  private langsearchKey = "sk-ed72ffcf8ca147c9a929ed588c93a82e";

  private async withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 1000): Promise<T> {
    try {
      return await fn();
    } catch (error: any) {
      const errorStr = JSON.stringify(error).toUpperCase();
      const isQuotaError = 
        errorStr.includes('429') || 
        errorStr.includes('RESOURCE_EXHAUSTED') || 
        errorStr.includes('QUOTA') ||
        errorStr.includes('RATE_LIMIT');

      if (isQuotaError && retries > 0) {
        await sleep(delay);
        return this.withRetry(fn, retries - 1, delay * 2);
      }
      throw error;
    }
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on this synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up inquiries for "${query}". JSON array only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateTopicImage(query: string): Promise<string | undefined> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `A formal, sophisticated conceptual visual for: "${query}". Minimalist tech aesthetic, deep blacks, cyan neon accents, ultra-high definition.` }],
        },
        config: { imageConfig: { aspectRatio: "16:9" } },
      });
      const part = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
      return part ? `data:image/png;base64,${part.inlineData.data}` : undefined;
    } catch { return undefined; }
  }

  // IMPLEMENTATION: Alternative path for Enhanced Answers using Langsearch SDK format
  private async *streamLangsearchFallback(query: string): AsyncGenerator<StreamResponse> {
    try {
      const response = await fetch('https://api.langsearch.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.langsearchKey}`
        },
        body: JSON.stringify({
          model: "langsearch-enhanced-1",
          messages: [
            { role: "system", content: "You are the Enhanced Spark Search Engine. Your goal is to provide deep, exhaustive real-time analysis when standard paths are saturated." }, 
            { role: "user", content: query }
          ],
          stream: true
        })
      });

      if (!response.ok) throw new Error("Enhanced Uplink Failure");

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (reader) {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          const chunk = decoder.decode(value);
          // Yield chunk with isEnhanced: true to trigger UI changes
          yield { text: chunk, done: false, sources: [], isEnhanced: true };
        }
      }
      yield { text: "", done: true, sources: [], isEnhanced: true };
    } catch (e) {
      yield { text: "\n\n**Critical Interference.** Local synthesis engaged. Search results may be limited.", done: true, sources: [] };
    }
  }

  async *streamSearch(query: string, file?: AttachedFile): AsyncGenerator<StreamResponse> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: query }];
    if (file) {
      parts.push({ inlineData: { data: file.data, mimeType: file.mimeType } });
    }

    try {
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: { parts },
        config: {
          systemInstruction: "You are Spark, a specialized high-performance AI Search Engine. Fetch real-time data and synthesize it into clear, accurate summaries with citations.",
          tools: [{ googleSearch: {} }],
          temperature: 0.1,
        },
      });

      let finalSources: Array<{ title: string; uri: string }> = [];

      for await (const chunk of result) {
        const text = chunk.text || "";
        const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
        const chunks = groundingMetadata?.groundingChunks;

        if (chunks) {
          chunks.forEach(c => {
            if (c.web && c.web.uri) {
              if (!finalSources.find(s => s.uri === c.web!.uri)) {
                finalSources.push({ title: c.web.title || "Source", uri: c.web.uri });
              }
            }
          });
        }
        yield { text, done: false, sources: [] };
      }
      yield { text: "", done: true, sources: finalSources };
    } catch (error: any) {
      const errStr = JSON.stringify(error).toUpperCase();
      // IMPLEMENTATION: Catching Quota limits and switching to Langsearch path
      if (errStr.includes('QUOTA') || errStr.includes('429') || errStr.includes('RESOURCE_EXHAUSTED')) {
        console.warn("Switching to Enhanced Langsearch Path...");
        yield* this.streamLangsearchFallback(query);
      } else {
        throw new Error('Neural Synthesis Error');
      }
    }
  }
}

