import { GoogleGenAI, Type } from "@google/genai";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

export interface StreamResponse {
  text: string;
  done: boolean;
  sources: Array<{ title: string; uri: string }>;
  isEnhanced?: boolean;
  isCached?: boolean;
}

interface CacheEntry {
  text: string;
  sources: Array<{ title: string; uri: string }>;
  relatedQueries: string[];
  timestamp: number;
}

const CACHE_TTL = 3600000; // 1 hour

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  private langsearchKey = "sk-ed72ffcf8ca147c9a929ed588c93a82e";
  private cache: Record<string, CacheEntry> = {};

  constructor() {
    try {
      const saved = localStorage.getItem('spark_agi_cache');
      if (saved) {
        this.cache = JSON.parse(saved);
        this.cleanupCache();
      }
    } catch (e) { console.warn("Cache initialization failed"); }
  }

  private cleanupCache() {
    const now = Date.now();
    Object.keys(this.cache).forEach(key => {
      if (now - this.cache[key].timestamp > CACHE_TTL) {
        delete this.cache[key];
      }
    });
  }

  private persistCache() {
    try {
      localStorage.setItem('spark_agi_cache', JSON.stringify(this.cache));
    } catch (e) { /* Storage full or disabled */ }
  }

  private getCacheKey(query: string, file?: AttachedFile): string {
    const fileHash = file ? file.data.substring(0, 32) : 'no-file';
    return `${query.trim().toLowerCase()}_${fileHash}`;
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on this synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up inquiries for "${query}". JSON array only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  private async *streamLangsearchFallback(query: string): AsyncGenerator<StreamResponse> {
    try {
      const response = await fetch('https://api.langsearch.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.langsearchKey}`
        },
        body: JSON.stringify({
          model: "langsearch-enhanced-1",
          messages: [{ role: "system", content: "Vayu AGI Enhanced Path: High-fidelity real-time search synthesis for Spark." }, { role: "user", content: query }],
          stream: true
        })
      });

      if (!response.ok) throw new Error("Fallback Fail");

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (reader) {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          const chunk = decoder.decode(value);
          yield { text: chunk, done: false, sources: [], isEnhanced: true };
        }
      }
      yield { text: "", done: true, sources: [], isEnhanced: true };
    } catch (e) {
      yield { text: "Uplink Interference. Local Vayu mode active.", done: true, sources: [] };
    }
  }

  async *streamSearch(query: string, file?: AttachedFile): AsyncGenerator<StreamResponse> {
    const cacheKey = this.getCacheKey(query, file);

    if (this.cache[cacheKey]) {
      const cached = this.cache[cacheKey];
      if (Date.now() - cached.timestamp < CACHE_TTL) {
        const words = cached.text.split(' ');
        for (let i = 0; i < words.length; i += 5) {
          await sleep(20);
          yield { 
            text: words.slice(i, i + 5).join(' ') + ' ', 
            done: false, 
            sources: [], 
            isCached: true
          };
        }
        yield { text: "", done: true, sources: cached.sources, isCached: true };
        return;
      }
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: query }];
    if (file) parts.push({ inlineData: { data: file.data, mimeType: file.mimeType } });

    let fullAccumulatedText = "";
    let finalSources: Array<{ title: string; uri: string }> = [];

    try {
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: { parts },
        config: {
          systemInstruction: "You are Vayu AGI, the synthesis engine powering Spark. Provide concise, accurate real-time summaries with citations. Always verify data against current web grounding.",
          tools: [{ googleSearch: {} }],
        },
      });

      for await (const chunk of result) {
        const text = chunk.text || "";
        fullAccumulatedText += text;
        const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
        const chunks = groundingMetadata?.groundingChunks;

        if (chunks) {
          chunks.forEach(c => {
            if (c.web?.uri && !finalSources.find(s => s.uri === c.web!.uri)) {
              finalSources.push({ title: c.web.title || "Source", uri: c.web.uri });
            }
          });
        }
        yield { text, done: false, sources: [] };
      }

      this.cache[cacheKey] = {
        text: fullAccumulatedText,
        sources: finalSources,
        relatedQueries: [],
        timestamp: Date.now()
      };
      this.persistCache();

      yield { text: "", done: true, sources: finalSources };
    } catch (error: any) {
      const errStr = JSON.stringify(error).toUpperCase();
      if (errStr.includes('QUOTA') || errStr.includes('429')) {
        yield* this.streamLangsearchFallback(query);
      } else {
        throw error;
      }
    }
  }

  updateCacheRelated(query: string, file: AttachedFile | null, related: string[]) {
    const key = this.getCacheKey(query, file || undefined);
    if (this.cache[key]) {
      this.cache[key].relatedQueries = related;
      this.persistCache();
    }
  }
}

