                               <div className={`thinking-spark-ring ${isSafeMode ? 'border-orange-500' : isEnhanced ? 'border-pink-500' : isCached ? 'border-green-400' : ''}`}></div>
                               <div className={`thinking-spark-core ${isSafeMode ? 'bg-orange-500' : isEnhanced ? 'bg-pink-500' : isCached ? 'bg-green-400' : ''}`}></div>
