type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isEnhanced, setIsEnhanced] = useState(false);
  const [isCached, setIsCached] = useState(false);
  const [isSafeMode, setIsSafeMode] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);

    const userMsgIdx = messages.length;
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze Payload" }]);
    setIsLoading(true);
    setIsEnhanced(false);
    setIsCached(false);
    setIsSafeMode(false);
    setError(null);

    const startTime = Date.now();
    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.searchWebImages(finalQuery || "Vayu Context");
      const stream = geminiService.streamSearch(finalQuery || "Context Synthesis", currentFile || undefined);

      let assistantMsgAdded = false;
      let accumulatedText = '';
      let currentEngine: UsageStats['engine'] = 'Gemini';

      for await (const chunk of stream) {
        if (chunk.isEnhanced) currentEngine = 'Langsearch';
        if (chunk.isSafeMode) {
           currentEngine = 'Vayu Safe Mode';
           setIsSafeMode(true);
        }
        if (chunk.isCached) {
          currentEngine = 'Local Cache';
          setIsCached(true);
        }

        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { 
              role: 'assistant', 
              content: accumulatedText, 
              usage: { estimatedTokens: 0, engine: currentEngine, isCached: chunk.isCached || false } 
            }]);
            assistantMsgAdded = true;
            // Initialize tab for this assistant message index
            setActiveTabs(prev => ({ ...prev, [userMsgIdx + 1]: 'synthesis' }));
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { 
                ...newMsgs[newMsgs.length - 1], 
                content: accumulatedText,
                usage: { estimatedTokens: 0, engine: currentEngine, isCached: chunk.isCached || false, latency: Date.now() - startTime }
              };
              return newMsgs;
            });
          }
        } else {
          const [finalImages, related] = await Promise.all([
            imageGenPromise,
            geminiService.generateRelatedQueries(finalQuery, accumulatedText)
          ]);

          geminiService.updateCacheRelated(finalQuery, currentFile, related);

          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              sources: chunk.sources,
              images: finalImages,
              relatedQueries: related,
              usage: { ...newMsgs[lastIdx].usage!, latency: Date.now() - startTime }
            };
            return newMsgs;
          });
          setIsLoading(false);
        }
      }
    } catch (err: any) {
      setError("Uplink destabilized. Vayu AGI recalibrating connection parameters.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
