        <span className="text-[8px] text-white/30 uppercase font-black tracking-widest">Active Module</span>
        <span className="text-[10px] text-white/70 font-mono tracking-tight">{engineName}</span>
      </div>
    </div>
  );
};

type ViewMode = 'synthesis' | 'media' | 'references';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isEnhanced, setIsEnhanced] = useState(false);
  const [isCached, setIsCached] = useState(false);
  const [isSafeMode, setIsSafeMode] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);
  const [activeTabs, setActiveTabs] = useState<Record<number, ViewMode>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const suggestionRef = useRef<HTMLDivElement>(null);

  const toggleVoiceSearch = useCallback(async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.onstart = () => setIsListening(true);
      recognition.onresult = (event: any) => { setQuery(event.results[0][0].transcript); setIsListening(false); };
      recognition.onend = () => setIsListening(false);
      recognitionRef.current = recognition;
      recognition.start();
    } catch (err) { setIsListening(false); }
  }, [isListening]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(async () => {
      if (query.trim().length >= 2 && !isLoading) {
        const fetched = await geminiService.getSuggestions(query);
        setSuggestions(fetched);
        setShowSuggestions(fetched.length > 0);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(timeout);
  }, [query, isLoading]);

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    e?.preventDefault();
    const finalQuery = (overrideQuery || query).trim();
    if ((!finalQuery && !attachedFile) || isLoading) return;

    setQuery('');
    setSuggestions([]);
    setShowSuggestions(false);

    const userMsgIdx = messages.length;
    setMessages(prev => [...prev, { role: 'user', content: finalQuery || "Analyze Payload" }]);
    setIsLoading(true);
    setIsEnhanced(false);
    setIsCached(false);
    setIsSafeMode(false);
    setError(null);

    const startTime = Date.now();
    const currentFile = attachedFile;
    setAttachedFile(null);

    try {
      const imageGenPromise = geminiService.searchWebImages(finalQuery || "Vayu Context");
      const stream = geminiService.streamSearch(finalQuery || "Context Synthesis", currentFile || undefined);

      let assistantMsgAdded = false;
      let accumulatedText = '';
      let currentEngine: UsageStats['engine'] = 'Gemini';

      for await (const chunk of stream) {
        if (chunk.isEnhanced) {
          currentEngine = 'Langsearch';
          setIsEnhanced(true);
        }
        if (chunk.isSafeMode) {
           currentEngine = 'Vayu Safe Mode';
           setIsSafeMode(true);
        }
        if (chunk.isCached) {
          currentEngine = 'Local Cache';
          setIsCached(true);
        }

        if (!chunk.done) {
          accumulatedText += chunk.text;
          if (!assistantMsgAdded) {
            setMessages(prev => [...prev, { 
              role: 'assistant', 
              content: accumulatedText, 
              usage: { estimatedTokens: 0, engine: currentEngine, isCached: chunk.isCached || false } 
            }]);
            assistantMsgAdded = true;
            setActiveTabs(prev => ({ ...prev, [userMsgIdx + 1]: 'synthesis' }));
          } else {
            setMessages(prev => {
              const newMsgs = [...prev];
              newMsgs[newMsgs.length - 1] = { 
                ...newMsgs[newMsgs.length - 1], 
                content: accumulatedText,
                usage: { estimatedTokens: 0, engine: currentEngine, isCached: chunk.isCached || false, latency: Date.now() - startTime }
              };
              return newMsgs;
            });
          }
        } else {
          const [finalImages, related] = await Promise.all([
            imageGenPromise,
            geminiService.generateRelatedQueries(finalQuery, accumulatedText)
          ]);

          geminiService.updateCacheRelated(finalQuery, currentFile, related);

          setMessages(prev => {
            const newMsgs = [...prev];
            const lastIdx = newMsgs.length - 1;
            newMsgs[lastIdx] = { 
              ...newMsgs[lastIdx], 
              sources: chunk.sources,
              images: finalImages,
              relatedQueries: related,
              usage: { ...newMsgs[lastIdx].usage!, latency: Date.now() - startTime }
            };
            return newMsgs;
          });
          setIsLoading(false);
        }
      }
    } catch (err: any) {
      setError("Uplink destabilized. Vayu AGI recalibrating connection parameters.");
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const hasHistory = messages.length > 0;
  const canSubmit = query.trim().length > 0 || attachedFile !== null;

  const ghostText = useMemo(() => {
    if (!query || suggestions.length === 0) return '';
    const firstMatch = suggestions[0];
    if (firstMatch.toLowerCase().startsWith(query.toLowerCase())) {
      return firstMatch.slice(query.length);
    }
    return '';
  }, [query, suggestions]);

  return (
    <div className="relative h-screen w-full flex flex-col bg-[#010103] overflow-hidden font-sans selection:bg-cyan-500/20">
      <CustomCursor />
      <Background />
      <FloatingElements />
      {error && <ErrorNotification message={error} onClose={() => setError(null)} />}

      <header className={`layout-transition fixed top-0 w-full z-[60] flex items-center px-6 sm:px-16 ${
        hasHistory ? 'h-20 header-glass' : 'h-[32vh] sm:h-[38vh] items-end justify-center pb-8'
      } ${isLoading ? 'header-loading-glow' : ''}`}>
        <SparkleTitle hasHistory={hasHistory} isLoading={isLoading} />
        {isSafeMode && (
           <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 px-4 py-1 rounded-full bg-orange-500/10 border border-orange-500/30 text-[9px] font-black text-orange-400 uppercase tracking-[0.4em] animate-pulse shadow-xl">
             Vayu Safe Mode
           </div>
        )}
        {hasHistory && <div className="header-accent-line" />}
      </header>

      <main 
        ref={scrollRef}
        className={`flex-1 w-full max-w-[920px] mx-auto px-4 sm:px-12 overflow-y-auto pt-28 sm:pt-36 pb-64 transition-all duration-1000 custom-scroll ${hasHistory ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}
      >
        <div className="flex flex-col gap-12 sm:gap-18">
          {messages.map((msg, idx) => (
            <div key={idx} className="group/msg animate-result flex flex-col w-full relative">
              {msg.role === 'user' ? (
                <div className="flex flex-col gap-1 py-8 px-4">
                   <div className="flex items-center gap-5 sm:gap-7">
                    <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-xl bg-white/[0.05] border border-white/10 flex items-center justify-center text-[10px] font-black text-white/40 shrink-0 shadow-lg rotate-2 uppercase tracking-tighter">Query</div>
                    <h2 className="text-xl sm:text-2xl md:text-3xl font-light text-white/95 tracking-tight leading-snug">{msg.content}</h2>
                  </div>
                  {idx === messages.length - 1 && isLoading && !messages.find((m, i) => i > idx) && (
                    <div className="pl-13 sm:pl-17">
                      <ThinkingIndicator isEnhanced={isEnhanced} isCached={isCached} isSafeMode={isSafeMode} />
                    </div>
                  )}
                </div>
              ) : (
                <div className="flex flex-col border border-white/[0.08] bg-white/[0.02] backdrop-blur-[60px] rounded-[2rem] sm:rounded-[2.8rem] overflow-hidden shadow-2xl transition-all ring-1 ring-white/5 relative">
                  <div className="flex flex-wrap items-center px-5 sm:px-8 py-4 border-b border-white/[0.03] bg-white/[0.02] gap-2">
                    <div className="flex bg-white/[0.05] p-1 rounded-full gap-0.5 border border-white/5">
                      {['synthesis', 'media', 'references'].map((tab) => (
                        <button
                          key={tab}
                          onClick={() => setActiveTabs(prev => ({ ...prev, [idx]: tab as ViewMode }))}
                          className={`px-4 sm:px-7 py-1.5 rounded-full text-[9px] sm:text-[10px] font-bold uppercase tracking-[0.2em] transition-all duration-300 ${
                            (activeTabs[idx] || 'synthesis') === tab 
                            ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/15' 
                            : 'text-white/30 hover:text-white/70'
                          }`}
                        >
                          {tab === 'references' ? 'Sources' : tab}
                        </button>
                      ))}
                    </div>
                    <UsageBadge usage={msg.usage} />
                  </div>

                  <div className="p-7 sm:p-12 min-h-[200px]">
                    {(activeTabs[idx] || 'synthesis') === 'synthesis' && (
                      <div className="animate-fade-scale">
                        <FormattedContent content={msg.content} />
                        {idx === messages.length - 1 && isLoading && msg.content && (
                          <div className="flex items-center gap-4 mt-6 opacity-40">
                             <div className="thinking-spark-container scale-[0.6]">
                               <div className={`thinking-spark-ring ${isSafeMode ? 'border-orange-500' : isEnhanced ? 'border-pink-500' : isCached ? 'border-green-400' : 'border-cyan-400'}`}></div>
                               <div className={`thinking-spark-core ${isSafeMode ? 'bg-orange-500' : isEnhanced ? 'bg-pink-500' : isCached ? 'bg-green-400' : 'bg-cyan-400'}`}></div>
                             </div>
                             <span className={`text-[9px] font-bold uppercase tracking-[0.4em] ${isSafeMode ? 'text-orange-400' : isEnhanced ? 'text-pink-400' : isCached ? 'text-green-400' : 'text-cyan-400'}`}>
                               {isSafeMode ? 'Safe Mode Syncing...' : 'Vayu AGI Stream...'}
                             </span>
                          </div>
                        )}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'media' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-8">
                        {msg.images?.map((img, i) => (
                          <div key={i} className="relative rounded-2xl sm:rounded-3xl overflow-hidden border border-white/10 aspect-video bg-black/90 shadow-xl group/img">
                            <img src={img} alt="Vayu Visual Artifact" className="w-full h-full object-cover opacity-80 group-hover/img:opacity-100 group-hover/img:scale-105 transition-all duration-700" />
                            <div className="absolute bottom-4 left-4 px-3 py-1 bg-black/60 backdrop-blur-md rounded-full border border-white/10">
                               <span className="text-[8px] font-black uppercase text-white/50 tracking-widest">Web Retrieval</span>
                            </div>
                          </div>
                        )) || <div className="h-40 border border-dashed border-white/10 rounded-2xl flex items-center justify-center opacity-30 text-[9px] uppercase tracking-[0.5em] font-black">No media artifacts retrieved</div>}
                      </div>
                    )}

                    {(activeTabs[idx] || 'synthesis') === 'references' && (
                      <div className="animate-fade-scale grid grid-cols-1 sm:grid-cols-2 gap-5">
                        {msg.sources?.length ? msg.sources.map((source, i) => (
                          <a key={i} href={source.uri} target="_blank" rel="noopener noreferrer" className="p-5 sm:p-7 rounded-[1.5rem] sm:rounded-[2rem] border border-white/10 bg-white/[0.03] hover:bg-cyan-500/10 hover:border-cyan-500/40 transition-all flex flex-col gap-3 group">
                            <h4 className="text-[13px] sm:text-[15px] font-bold text-white/90 group-hover:text-cyan-400 transition-colors line-clamp-1 leading-tight">{source.title}</h4>
                            <p className="text-[9px] text-cyan-400/50 font-mono tracking-tighter uppercase truncate">{new URL(source.uri).hostname}</p>
                          </a>
                        )) : <div className="col-span-2 text-center opacity-20 py-16 uppercase tracking-[0.5em] text-[10px] font-black">Accuracy confirmation archived</div>}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}

          {!isLoading && messages.length > 0 && (
            <section className="animate-result flex flex-col gap-8 pt-6 pb-24">
              <div className="flex items-center gap-4 px-2">
                <div className="h-px flex-grow bg-gradient-to-r from-transparent via-cyan-500/20 to-transparent" />
                <div className="flex items-center gap-3">
                  <div className="relative flex h-2 w-2">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-cyan-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-cyan-500"></span>
                  </div>
                  <h3 className="text-[11px] font-black text-cyan-400/60 uppercase tracking-[0.5em] whitespace-nowrap">Vayu Neural Bridge</h3>
                </div>
                <div className="h-px flex-grow bg-gradient-to-r from-transparent via-cyan-500/20 to-transparent" />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-5">
                {(messages[messages.length-1].relatedQueries || ["Explore world news", "Vayu Research Hub", "Neural economic index"]).map((text, i) => (
                  <button
                    key={i}
                    onClick={() => handleSearch(undefined, text)}
                    className="p-6 sm:p-9 rounded-[2rem] sm:rounded-[2.5rem] border border-white/10 bg-white/[0.015] backdrop-blur-md hover:bg-cyan-500/[0.03] hover:border-cyan-500/40 transition-all text-left group shadow-lg ring-1 ring-white/5 relative overflow-hidden"
                  >
                    <div className="w-10 h-10 rounded-2xl bg-cyan-500/10 flex items-center justify-center text-cyan-400 mb-5 group-hover:scale-110 group-hover:bg-cyan-500/20 transition-all group-hover:rotate-12">
                      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 6v12a3 3 0 1 0 3-3H6a3 3 0 1 0 3 3V6a3 3 0 1 0-3 3h12a3 3 0 1 0-3-3z"/></svg>
                    </div>
                    <span className="text-[13px] sm:text-[14px] text-white/50 group-hover:text-white transition-colors line-clamp-2 leading-relaxed font-medium tracking-tight">{text}</span>
                  </button>
                ))}
              </div>
            </section>
          )}
        </div>
      </main>

      <div className={`fixed left-0 right-0 px-4 flex flex-col items-center z-[70] transition-all duration-1000 ${hasHistory ? 'bottom-6 sm:bottom-10' : 'top-[50vh] -translate-y-1/2'}`}>
        <div className="w-full max-w-2xl flex flex-col items-center relative">

          <form onSubmit={handleSearch} className="w-full relative group/form">
            <div className={`flex items-center relative rounded-[2rem] sm:rounded-[2.5rem] transition-all duration-700 search-glass search-focus-glow ring-1 ring-white/10 ${isLoading ? 'border-cyan-500/60 shadow-[0_0_40px_rgba(34,211,238,0.2)]' : ''}`}>

              <div className="flex-shrink-0 pl-4 sm:pl-7 pr-1">
                {/* BLINKING SPARK ICON IN INPUT */}
                <div className="w-10 h-10 flex items-center justify-center relative">
                  <div className={`absolute inset-0 rounded-full border border-cyan-400/20 ${isLoading ? 'animate-spin' : ''}`} />
                  <div className={`w-2.5 h-2.5 bg-cyan-400 rounded-full shadow-[0_0_8px_rgba(34,211,238,1)] ${!isLoading ? 'animate-pulse' : 'animate-ping'}`} />
                </div>
              </div>

              <div className="flex-grow relative flex items-center">
                {ghostText && (
                  <div className="absolute left-2.5 pointer-events-none text-white/20 text-sm sm:text-lg font-light tracking-tight whitespace-pre select-none">
                    <span className="opacity-0">{query}</span>
                    <span>{ghostText}</span>
                  </div>
                )}
                <input
                  type="text" value={query} 
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Tab' && ghostText) {
                      e.preventDefault();
                      setQuery(query + ghostText);
                    }
                  }}
                  placeholder={isListening ? "Listening..." : "Ask Spark..."}
                  onFocus={() => { if(query.length >= 2) setShowSuggestions(true); }}
                  className="w-full bg-transparent px-2.5 py-4 sm:py-5 text-white placeholder-white/20 focus:outline-none text-sm sm:text-lg font-light tracking-tight relative z-10"
                  autoFocus
                />
              </div>

              <div className="flex-shrink-0 pr-4 sm:pr-6 flex items-center gap-1.5 sm:gap-2.5">
                <button type="button" onClick={() => fileInputRef.current?.click()} className={`p-2.5 rounded-lg transition-all ${attachedFile ? 'bg-cyan-500 text-black shadow-md shadow-cyan-500/40' : 'text-white/35 hover:text-cyan-400'}`}>
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l8.57-8.57a4 4 0 1 1 5.66 5.66l-8.59 8.51a2 2 0 0 1-2.83-2.83l8.49-8.48" /></svg>
                </button>
                <input type="file" ref={fileInputRef} className="hidden" onChange={async (e) => {
                  const file = e.target.files?.[0];
                  if (file) {
                    const reader = new FileReader();
                    reader.onloadend = () => setAttachedFile({ data: (reader.result as string).split(',')[1], mimeType: file.type });
                    reader.readAsDataURL(file);
                  }
                }} />
                <button type="button" onClick={toggleVoiceSearch} className={`p-2.5 rounded-full transition-colors ${isListening ? 'bg-red-500/60 text-white animate-pulse shadow-[0_0_10px_rgba(239,68,68,0.5)]' : 'text-white/10 hover:text-cyan-400'}`}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/></svg>
                </button>
                <button type="submit" disabled={!canSubmit || isLoading} className={`p-3.5 sm:p-4 rounded-full transition-all duration-700 ${canSubmit ? 'bg-cyan-500 text-black shadow-md shadow-cyan-500/40 active:scale-95' : 'bg-white/5 text-white/10 opacity-30'}`}>
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><path d="M5 12h14m-7-7 7 7-7 7"/></svg>
                </button>
              </div>
            </div>

            {/* Google-style Dropdown Suggestions */}
            {showSuggestions && suggestions.length > 0 && query.length >= 2 && (
              <div 
                ref={suggestionRef}
                className="absolute top-full left-0 right-0 mt-3 bg-black/60 backdrop-blur-2xl border border-white/10 rounded-[2rem] overflow-hidden shadow-[0_20px_50px_rgba(0,0,0,0.5)] z-[80] animate-in fade-in slide-in-from-top-2 duration-300 ring-1 ring-white/5"
              >
                <div className="py-3">
                  {suggestions.map((s, i) => (
                    <button
                      key={i}
                      type="button"
                      onClick={() => handleSearch(undefined, s)}
                      className="w-full px-8 py-4 text-left hover:bg-white/5 flex items-center gap-5 group transition-colors"
                    >
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-white/20 group-hover:text-cyan-400"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                      <span className="text-white/60 group-hover:text-white text-[15px] font-medium tracking-tight">
                        {s.toLowerCase().startsWith(query.toLowerCase()) ? (
                          <>
                            <span className="text-white/30">{s.slice(0, query.length)}</span>
                            <span>{s.slice(query.length)}</span>
                          </>
                        ) : s}
                      </span>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </form>
        </div>
      </div>

      {!hasHistory && (
        <div className="fixed bottom-10 w-full flex flex-col items-center gap-8 animate-result delay-500">
          <div className="flex flex-wrap justify-center gap-4 sm:gap-10 px-6">
            <button onClick={() => handleSearch(undefined, "Global financial summary")} className="text-[10px] sm:text-[11px] uppercase tracking-[0.3em] text-white/50 hover:text-cyan-400 transition-all border border-white/10 px-7 py-2.5 rounded-full search-glass font-bold shadow-sm">Markets</button>
            <button onClick={() => handleSearch(undefined, "Latest AI breakthroughs")} className="text-[10px] sm:text-[11px] uppercase tracking-[0.3em] text-white/50 hover:text-cyan-400 transition-all border border-white/10 px-7 py-2.5 rounded-full search-glass font-bold shadow-sm">Neural Hub</button>
            <button onClick={() => handleSearch(undefined, "Real-time world news")} className="text-[10px] sm:text-[11px] uppercase tracking-[0.3em] text-white/50 hover:text-cyan-400 transition-all border border-white/10 px-7 py-2.5 rounded-full search-glass font-bold shadow-sm">Global News</button>
          </div>
          <div className="flex justify-center gap-10 sm:gap-48 text-[11px] uppercase tracking-[2em] text-white/5 pointer-events-none select-none font-black antialiased opacity-30">
            <span>Spark Interface</span>
            <span>Vayu AGI Architecture</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

export interface StreamResponse {
  text: string;
  done: boolean;
  sources: Array<{ title: string; uri: string }>;
  isEnhanced?: boolean;
  isCached?: boolean;
  isSafeMode?: boolean;
}

interface CacheEntry {
  text: string;
  sources: Array<{ title: string; uri: string }>;
  relatedQueries: string[];
  timestamp: number;
}

const CACHE_TTL = 3600000; // 1 hour

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  private langsearchKey = "sk-ed72ffcf8ca147c9a929ed588c93a82e";
  private cache: Record<string, CacheEntry> = {};

  constructor() {
    try {
      const saved = localStorage.getItem('spark_agi_cache');
      if (saved) {
        this.cache = JSON.parse(saved);
        this.cleanupCache();
      }
    } catch (e) { console.warn("Cache initialization failed"); }
  }

  private cleanupCache() {
    const now = Date.now();
    Object.keys(this.cache).forEach(key => {
      if (now - this.cache[key].timestamp > CACHE_TTL) {
        delete this.cache[key];
      }
    });
  }

  private persistCache() {
    try {
      localStorage.setItem('spark_agi_cache', JSON.stringify(this.cache));
    } catch (e) { /* Storage full or disabled */ }
  }

  private getCacheKey(query: string, file?: AttachedFile): string {
    const fileHash = file ? file.data.substring(0, 32) : 'no-file';
    return `${query.trim().toLowerCase()}_${fileHash}`;
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on this synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up inquiries for "${query}". Return only a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async searchWebImages(query: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Identify 3 visually striking keywords for: "${query}". Return as a comma-separated list.`,
      });
      const keywords = (response.text || query).split(',').map(s => s.trim().toLowerCase());
      return keywords.map((kw, i) => `https://loremflickr.com/1200/800/${encodeURIComponent(kw)}?lock=${i}`).slice(0, 3);
    } catch {
      return [`https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1200`];
    }
  }

  private async *streamLangsearchFallback(query: string): AsyncGenerator<StreamResponse> {
    try {
      const response = await fetch('https://api.langsearch.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.langsearchKey}`
        },
        body: JSON.stringify({
          model: "langsearch-enhanced-1",
          messages: [{ role: "user", content: `You are a high-efficiency search engine. Synthesize web data for: ${query}. Use markdown formatting.` }],
          stream: true
        })
      });

      if (!response.ok) throw new Error("Fallback failed");

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (reader) {
        let buffer = "";
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || "";

          for (const line of lines) {
            const cleanLine = line.trim();
            if (cleanLine.startsWith('data: ')) {
              const dataStr = cleanLine.substring(6);
              if (dataStr === '[DONE]') break;
              try {
                const json = JSON.parse(dataStr);
                const content = json.choices?.[0]?.delta?.content || "";
                if (content) {
                  yield { text: content, done: false, sources: [], isEnhanced: true };
                }
              } catch (e) {
                // Not JSON or partial chunk
              }
            }
          }
        }
      }
      yield { text: "", done: true, sources: [], isEnhanced: true };
    } catch {
      yield* this.streamSafeModeFallback(query);
    }
  }

  private async *streamSafeModeFallback(query: string): AsyncGenerator<StreamResponse> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `Synthesize an expert response using your internal high-density training data for: "${query}". External web-uplink is restricted.`,
      });

      for await (const chunk of result) {
        yield { text: chunk.text || "", done: false, sources: [], isSafeMode: true };
      }
      yield { text: "", done: true, sources: [], isSafeMode: true };
    } catch {
      yield { text: "System Failure. AGI Core Offline. Please verify API configuration.", done: true, sources: [] };
    }
  }

  async *streamSearch(query: string, file?: AttachedFile): AsyncGenerator<StreamResponse> {
    const cacheKey = this.getCacheKey(query, file);

    if (this.cache[cacheKey]) {
      const cached = this.cache[cacheKey];
      if (Date.now() - cached.timestamp < CACHE_TTL) {
        const words = cached.text.split(' ');
        for (let i = 0; i < words.length; i += 5) {
          await sleep(20);
          yield { text: words.slice(i, i + 5).join(' ') + ' ', done: false, sources: [], isCached: true };
        }
        yield { text: "", done: true, sources: cached.sources, isCached: true };
        return;
      }
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: query }];
    if (file) parts.push({ inlineData: { data: file.data, mimeType: file.mimeType } });

    let fullAccumulatedText = "";
    let finalSources: Array<{ title: string; uri: string }> = [];

    try {
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: { parts },
        config: {
          systemInstruction: "You are Vayu AGI. Use Google Search grounding for real-time verification. Structure with Markdown.",
          tools: [{ googleSearch: {} }],
        },
      });

      for await (const chunk of result) {
        const text = chunk.text || "";
        fullAccumulatedText += text;
        const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
        if (groundingMetadata?.groundingChunks) {
          groundingMetadata.groundingChunks.forEach(c => {
            if (c.web?.uri && !finalSources.find(s => s.uri === c.web!.uri)) {
              finalSources.push({ title: c.web.title || "Web Reference", uri: c.web.uri });
            }
          });
        }
        yield { text, done: false, sources: [] };
      }

      this.cache[cacheKey] = {
        text: fullAccumulatedText,
        sources: finalSources,
        relatedQueries: [],
        timestamp: Date.now()
      };
      this.persistCache();

      yield { text: "", done: true, sources: finalSources };
    } catch (error: any) {
      // Forceful fallback on error
      yield* this.streamLangsearchFallback(query);
    }
  }

  updateCacheRelated(query: string, file: AttachedFile | null, related: string[]) {
    const key = this.getCacheKey(query, file || undefined);
    if (this.cache[key]) {
      this.cache[key].relatedQueries = related;
      this.persistCache();
    }
  }
}

