import { GoogleGenAI, Type } from "@google/genai";

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

export interface StreamResponse {
  text: string;
  done: boolean;
  sources: Array<{ title: string; uri: string }>;
  isEnhanced?: boolean;
  isCached?: boolean;
  isSafeMode?: boolean;
  step?: string;
}

interface CacheEntry {
  text: string;
  sources: Array<{ title: string; uri: string }>;
  relatedQueries: string[];
  timestamp: number;
}

const CACHE_TTL = 3600000; // 1 hour

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class GeminiService {
  private langsearchKey = "sk-ed72ffcf8ca147c9a929ed588c93a82e";
  private searxngBase = "https://search.disroot.org/search";
  private cache: Record<string, CacheEntry> = {};

  constructor() {
    try {
      const saved = localStorage.getItem('spark_agi_cache');
      if (saved) {
        this.cache = JSON.parse(saved);
        this.cleanupCache();
      }
    } catch (e) { console.warn("Cache initialization failed"); }
  }

  private cleanupCache() {
    const now = Date.now();
    Object.keys(this.cache).forEach(key => {
      if (now - this.cache[key].timestamp > CACHE_TTL) {
        delete this.cache[key];
      }
    });
  }

  private persistCache() {
    try {
      localStorage.setItem('spark_agi_cache', JSON.stringify(this.cache));
    } catch (e) { /* Storage full or disabled */ }
  }

  private getCacheKey(query: string, file?: AttachedFile): string {
    const fileHash = file ? file.data.substring(0, 32) : 'no-file';
    return `${query.trim().toLowerCase()}_${fileHash}`;
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on this synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up inquiries for "${query}". Return only a JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      });
      return JSON.parse(response.text || "[]");
    } catch { return []; }
  }

  async searchWebImages(query: string): Promise<string[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Identify 3 visually striking stock-photo keywords for: "${query}". Return as a comma-separated list.`,
      });
      const keywords = (response.text || query).split(',').map(s => s.trim().toLowerCase());
      return keywords.map((kw, i) => `https://loremflickr.com/1200/800/${encodeURIComponent(kw)}?lock=${i}`).slice(0, 3);
    } catch {
      return [`https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1200`];
    }
  }

  private async *streamSearXNGFallback(query: string): AsyncGenerator<StreamResponse> {
    yield { text: "", done: false, sources: [], step: "Primary uplink failed. Engaging Disroot SearXNG Tier..." };

    try {
      const url = `${this.searxngBase}?q=${encodeURIComponent(query)}&format=json&safesearch=1`;
      const response = await fetch(url);

      if (!response.ok) throw new Error(`SearXNG Node HTTP ${response.status}`);

      const data = await response.json();
      const results = data.results || [];

      if (results.length === 0) throw new Error("Zero search artifacts retrieved from SearXNG.");

      const snippets = results.slice(0, 6).map((r: any) => `Title: ${r.title}\nURL: ${r.url}\nExcerpt: ${r.content || r.snippet}`).join("\n\n");
      const sources = results.slice(0, 6).map((r: any) => ({ title: r.title, uri: r.url }));

      yield { text: "", done: false, sources: [], step: "Neural processing of SearXNG artifacts..." };

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `Synthesize a high-fidelity answer for "${query}" based ONLY on these data fragments:\n\n${snippets}\n\nUse Markdown for formatting.`,
      });

      for await (const chunk of result) {
        yield { text: chunk.text || "", done: false, sources: [], isEnhanced: true };
      }
      yield { text: "", done: true, sources };
    } catch (e) {
      console.warn("SearXNG Tier failure, falling back to Langsearch Node:", e);
      yield* this.streamLangsearchFallback(query);
    }
  }

  private async *streamLangsearchFallback(query: string): AsyncGenerator<StreamResponse> {
    yield { text: "", done: false, sources: [], step: "Secondary tier offline. Re-routing to Langsearch Node..." };
    try {
      const response = await fetch('https://api.langsearch.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.langsearchKey}`
        },
        body: JSON.stringify({
          model: "langsearch-enhanced-1",
          messages: [
            { role: "system", content: "You are Spark's emergency synthesis core. Ground your answer in web data. Use Markdown." },
            { role: "user", content: query }
          ],
          stream: true
        })
      });

      if (!response.ok) throw new Error(`Langsearch node returned HTTP ${response.status}`);

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (reader) {
        let buffer = "";
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || "";

          for (const line of lines) {
            const cleanLine = line.trim();
            if (cleanLine === 'data: [DONE]') continue;
            if (cleanLine.startsWith('data: ')) {
              try {
                const json = JSON.parse(cleanLine.substring(6));
                const text = json.choices?.[0]?.delta?.content || "";
                if (text) yield { text, done: false, sources: [], isEnhanced: true };
              } catch (e) { }
            }
          }
        }
      }
      yield { text: "", done: true, sources: [], isEnhanced: true };
    } catch (e) {
      console.warn("Langsearch Node failure, accessing Safe Mode:", e);
      yield* this.streamSafeModeFallback(query);
    }
  }

  private async *streamSafeModeFallback(query: string): AsyncGenerator<StreamResponse> {
    yield { text: "", done: false, sources: [], step: "All search uplinks unavailable. Vayu Safe Mode active..." };
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `Synthesize an authoritative expert response based on internal knowledge for: "${query}". Explicitly state that search is offline and internal logic is active.`,
      });

      for await (const chunk of result) {
        yield { text: chunk.text || "", done: false, sources: [], isSafeMode: true };
      }
      yield { text: "", done: true, sources: [], isSafeMode: true };
    } catch {
      yield { text: "CRITICAL SYSTEM FAULT: Neural core logic disconnected. Synthesis impossible.", done: true, sources: [] };
    }
  }

  async *streamSearch(query: string, file?: AttachedFile): AsyncGenerator<StreamResponse> {
    const cacheKey = this.getCacheKey(query, file);

    if (this.cache[cacheKey]) {
      const cached = this.cache[cacheKey];
      if (Date.now() - cached.timestamp < CACHE_TTL) {
        yield { text: "", done: false, sources: [], step: "Retrieving from Neural Memory Cache..." };
        const words = cached.text.split(' ');
        for (let i = 0; i < words.length; i += 10) {
          await sleep(10);
          yield { text: words.slice(i, i + 10).join(' ') + ' ', done: false, sources: [], isCached: true };
        }
        yield { text: "", done: true, sources: cached.sources, isCached: true };
        return;
      }
    }

    yield { text: "", done: false, sources: [], step: "Establishing Vayu Primary Uplink..." };

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const parts: any[] = [{ text: query }];
      if (file) parts.push({ inlineData: { data: file.data, mimeType: file.mimeType } });

      const result = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: { parts },
        config: {
          systemInstruction: "You are Vayu AGI. Use Google Search grounding. Be detailed and formatted with Markdown.",
          tools: [{ googleSearch: {} }],
        },
      });

      let fullAccumulatedText = "";
      let finalSources: Array<{ title: string; uri: string }> = [];
      let hasStarted = false;

      for await (const chunk of result) {
        if (!hasStarted) {
          yield { text: "", done: false, sources: [], step: "Primary Node: Grounding verified." };
          hasStarted = true;
        }

        const text = chunk.text || "";
        fullAccumulatedText += text;

        const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
        if (groundingMetadata?.groundingChunks) {
          groundingMetadata.groundingChunks.forEach(c => {
            if (c.web?.uri && !finalSources.find(s => s.uri === c.web!.uri)) {
              finalSources.push({ title: c.web.title || "Reference", uri: c.web.uri });
            }
          });
        }
        yield { text, done: false, sources: [] };
      }

      this.cache[cacheKey] = {
        text: fullAccumulatedText,
        sources: finalSources,
        relatedQueries: [],
        timestamp: Date.now()
      };
      this.persistCache();

      yield { text: "", done: true, sources: finalSources };
    } catch (error: any) {
      console.warn("Primary Node failure, initiating Tiered Fallback (SearXNG/Langsearch).");
      yield* this.streamSearXNGFallback(query);
    }
  }

  updateCacheRelated(query: string, file: AttachedFile | null, related: string[]) {
    const key = this.getCacheKey(query, file || undefined);
    if (this.cache[key]) {
      this.cache[key].relatedQueries = related;
      this.persistCache();
    }
  }
}

