/**
 * Puter AI Service
 * Replaces Gemini with Puter.js openai/gpt-4o-mini + web_search
 */

declare const puter: any;

export interface AttachedFile {
  data: string; // base64
  mimeType: string;
}

export interface StreamResponse {
  text: string;
  done: boolean;
  sources: Array<{ title: string; uri: string }>;
  engine?: 'Puter AI (GPT-4o-mini)' | 'Local Cache';
  isCached?: boolean;
  step?: string;
}

interface CacheEntry {
  text: string;
  sources: Array<{ title: string; uri: string }>;
  relatedQueries: string[];
  timestamp: number;
  engine: string;
}

const CACHE_TTL = 3600000;

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export class PuterService {
  private cache: Record<string, CacheEntry> = {};

  constructor() {
    try {
      const saved = localStorage.getItem('spark_puter_cache');
      if (saved) {
        this.cache = JSON.parse(saved);
        this.cleanupCache();
      }
    } catch (e) { console.warn("Cache initialization failed"); }
  }

  private cleanupCache() {
    const now = Date.now();
    Object.keys(this.cache).forEach(key => {
      if (now - this.cache[key].timestamp > CACHE_TTL) {
        delete this.cache[key];
      }
    });
  }

  private persistCache() {
    try {
      localStorage.setItem('spark_puter_cache', JSON.stringify(this.cache));
    } catch (e) { }
  }

  private getCacheKey(query: string, file?: AttachedFile): string {
    const fileHash = file ? file.data.substring(0, 32) : 'no-file';
    return `${query.trim().toLowerCase()}_${fileHash}`;
  }

  async getSuggestions(input: string): Promise<string[]> {
    if (!input || input.length < 2) return [];
    try {
      // Puter suggestions via GPT-4o-mini
      const response = await puter.ai.chat(
        `Provide 4 logical search completions for: "${input}". Return ONLY a JSON array of strings. No extra text.`,
        { model: 'openai/gpt-4o-mini' }
      );
      const text = response.toString().trim();
      return JSON.parse(text.substring(text.indexOf('['), text.lastIndexOf(']') + 1));
    } catch { return []; }
  }

  async generateRelatedQueries(query: string, context: string): Promise<string[]> {
    try {
      const response = await puter.ai.chat(
        `Based on this search synthesis: "${context.substring(0, 400)}", generate 3 intelligent follow-up questions for "${query}". Return only a JSON array of strings. No extra text.`,
        { model: 'openai/gpt-4o-mini' }
      );
      const text = response.toString().trim();
      return JSON.parse(text.substring(text.indexOf('['), text.lastIndexOf(']') + 1));
    } catch { return []; }
  }

  async searchWebImages(query: string): Promise<string[]> {
    // Basic image keyword generation
    try {
      const response = await puter.ai.chat(
        `Identify 3 stock-photo keywords for: "${query}". Return as a comma-separated list. No extra text.`,
        { model: 'openai/gpt-4o-mini' }
      );
      const keywords = response.toString().split(',').map((s: string) => s.trim().toLowerCase());
      return keywords.map((kw: string, i: number) => `https://loremflickr.com/1200/800/${encodeURIComponent(kw)}?lock=${i}`).slice(0, 3);
    } catch {
      return [`https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1200`];
    }
  }

  async *streamSearch(query: string, file?: AttachedFile): AsyncGenerator<StreamResponse> {
    const cacheKey = this.getCacheKey(query, file);

    if (this.cache[cacheKey]) {
      const cached = this.cache[cacheKey];
      if (Date.now() - cached.timestamp < CACHE_TTL) {
        yield { text: "", done: false, sources: [], step: "Accessing Memory Cache..." };
        const words = cached.text.split(' ');
        for (let i = 0; i < words.length; i += 12) {
          await sleep(20);
          yield { text: words.slice(i, i + 12).join(' ') + ' ', done: false, sources: [], isCached: true, engine: 'Local Cache' };
        }
        yield { text: "", done: true, sources: cached.sources, isCached: true, engine: 'Local Cache' };
        return;
      }
    }

    yield { text: "", done: false, sources: [], step: "Establishing Puter.js Neural Bridge..." };

    try {
      yield { text: "", done: false, sources: [], step: "Searching the web with AI tools..." };

      // Use Puter.js Real-time Search
      const response = await puter.ai.chat(query, {
        model: 'openai/gpt-4o-mini',
        tools: [{ type: 'web_search' }]
      });

      const fullText = response.toString();

      yield { text: "", done: false, sources: [], step: "Synthesizing web artifacts..." };

      // Since puter.ai.chat v2 isn't natively streaming as an async iterator in this snippet, 
      // we reconstitute the "streaming" effect for the Spark UI.
      const words = fullText.split(' ');
      for (let i = 0; i < words.length; i += 8) {
        await sleep(15);
        yield { text: words.slice(i, i + 8).join(' ') + ' ', done: false, sources: [], engine: 'Puter AI (GPT-4o-mini)' };
      }

      this.cache[cacheKey] = {
        text: fullText,
        sources: [], // Puter handles sourcing internally in the markdown response
        relatedQueries: [],
        timestamp: Date.now(),
        engine: 'Puter AI (GPT-4o-mini)'
      };
      this.persistCache();

      yield { text: "", done: true, sources: [], engine: 'Puter AI (GPT-4o-mini)' };
    } catch (error: any) {
      console.error("Puter Error:", error);
      yield { text: "Error: Neural connection to Puter.js interrupted.", done: true, sources: [] };
    }
  }

  updateCacheRelated(query: string, file: AttachedFile | null, related: string[]) {
    const key = this.getCacheKey(query, file || undefined);
    if (this.cache[key]) {
      this.cache[key].relatedQueries = related;
      this.persistCache();
    }
  }
}

